INSERT INTO categories (id, slug, name, description, icon, image_url, intro, buying_criteria, journey, pitfalls, reading_list, related_slugs, seo_title, seo_description, hero_angle, sort_order, archived_at, created_at, updated_at) VALUES ('cat-1', 'crm', 'CRM', 'Where a fund''s relationships actually live. Founders, co-investors, LPs, angels — tracked from first DM to the next round.', '🤝', '/images/categories/crm.jpg', 'A CRM is a fund''s long-term memory. Every founder met at a demo day, every co-investor intro, every LP check-in, every "let''s talk in two quarters" — captured once, surfaced again when the next round, exit, or fund close suddenly makes it relevant. The good ones do this without anyone manually logging anything. The bad ones become Excel-with-extra-steps and get abandoned by Q3.

Indian VC dealflow doesn''t behave like a Salesforce funnel. Half the conversations start on WhatsApp; intros come through founder networks and angel syndicates; the same person is a founder one cycle and an angel investor the next. A working CRM here pulls from inbox, calendar, and LinkedIn natively, ideally enriches with India-specific signals — MCA filings, syndicate activity, Tracxn, Venture Intelligence, Inc42 — and lets the firm carry one contact graph across stages, sectors, and decades.', '[{"label":"Auto-capture from inbox and calendar.","description":"If your team has to manually log every meeting, the data decays inside a month."},{"label":"One contact graph across founder, angel, LP, co-investor.","description":"The same person plays multiple roles in Indian VC. The CRM has to know that."},{"label":"India-native enrichment.","description":"MCA, Tracxn, Venture Intelligence, Inc42, syndicate data — table stakes for any tool you''ll keep beyond a year."},{"label":"Plays well with the rest of the stack.","description":"Email, calendar, Notion or Slack, your data tools. A walled-garden CRM dies inside two quarters."}]', '{"beginner":"Notion. A single shared database for founders and conversations beats spreadsheets and beats nothing. Low cost, the rest of the stack can bolt on later.","intermediate":"A purpose-built CRM layered in. Folk, Streak, or HubSpot if your team lives in inbox; Notion stays as the wiki layer; Taghash if you want a fund-OS that already understands Indian LP and portfolio workflows.","advanced":"Affinity or Attio for relationship intelligence at scale; Clay layered on top for enrichment and outbound; Airtable for custom workflows; Taghash deepened across deal flow, portfolio, and LP comms."}', '[{"label":"Buying the global category leader and using 10% of it.","description":"Salesforce and HubSpot are powerful, but most Indian funds end up leaking the real data into WhatsApp anyway."},{"label":"A CRM that depends on manual logging.","description":"If the analyst has to remember to enter the note, it''ll be empty by the next IC. Pick one that listens."},{"label":"Treating CRM as a sourcing tool only.","description":"The compounding value is in the \"we met them in 2022, they were too early — what about now\" lookup, not the new-deal pipeline view."}]', '[]', '["data","research","portfolio-management","admin-ops"]', 'CRM for VCs · Top Tools in 2026 | VC Stack', 'The CRMs India''s top VCs actually use in 2026. Buying guide, editorial top picks (Affinity, Attio, Taghash), and honest comparisons for funds of every size.', 'The deal-flow operating system. How Indian VCs track founder relationships, pipeline, and portfolio signals — from first meeting to exit.', 0, NULL, 1777215011764, 1777215011764), ('cat-2', 'data', 'Data', 'Private-market databases, founder graphs, and registry-grade intel — the raw material every Indian VC memo is forged from.', '📈', '/images/categories/data.jpg', 'Data tools are the substrate of every workflow inside a fund: sourcing pipelines, comp pulls before a term sheet, sector mapping for thesis work, valuation triangulation, and the citation layer that turns a partner''s hunch into an IC-ready memo. The serious shift in the last 18 months is upstream — stealth detection from GitHub commits, domain registrations, and LinkedIn delta signals now beats waiting for a TechCrunch post by six to nine months. The fund that sees the founder first usually wins the round.

India breaks the global playbook. Tracxn is the benchmark for Indian coverage with a clean UI; Venture Intelligence has strong coverage but a weaker UI; PrivateCircle is improving fast. LinkedIn Sales Navigator has a data set you can''t buy anywhere else. EverTrace is genuinely strong on stealth founders and the founder graph. Crunchbase, CB Insights, and PitchBook thin out fast below Series B; Preqin is its own world for LP and fund data. MCA and RoC filings remain the only real source for cap-table and ESOP truth. Series A and below is still mostly opaque — expect to triangulate three sources for any number you put in writing.', '[{"label":"India coverage depth.","description":"Test the platform on twenty pre-Series-A Indian companies you know cold. If half are missing or stale, the platform is a global tool wearing an India hat."},{"label":"Fit-to-data-job.","description":"Stealth founders, closed rounds, LP intel, and sector benchmarking are different jobs. No tool wins all four — buy by the job that''s actually unblocked."},{"label":"UI and time-to-answer.","description":"Coverage matters; so does whether your analyst gets the answer out in two clicks. Tracxn''s UI is the benchmark."},{"label":"CRM integration.","description":"Native push into Affinity, Attio, Taghash, or Notion. Data that doesn''t land in your pipeline gets re-keyed once, then ignored forever."}]', '{"beginner":"Tracxn or Crunchbase plus LinkedIn Sales Navigator. Tracxn for India coverage and clean UI; LinkedIn for the data set nothing else has.","intermediate":"Add Venture Intelligence and PrivateCircle for deeper India depth. Stack by job: stealth founders go to EverTrace; Indian early-stage to Tracxn or VI; LP database to Preqin.","advanced":"Harmonic and EverTrace for predictive signal; CB Insights or PitchBook for global benchmarking; Sanchi Connect for India-LP intel. Everything wired into your CRM via Clay or direct connectors so analysts stop re-keying."}', '[{"label":"Buying enterprise tiers analysts never open.","description":"Adoption dies in week three without a named owner, weekly rituals, and a dashboard tracking active queries-per-seat."},{"label":"Treating one platform as ground truth.","description":"Every Indian data source misses something — early stage, regional, or a specific sector. Triangulate before you put a number in a memo."}]', '[]', '["crm","research","news","portfolio-management"]', 'Data Tools for VCs · Private Market Intelligence 2026', 'The private-market data stack Indian VCs run on in 2026. PitchBook, Harmonic, Tracxn, Venture Intelligence — picked for dealflow, diligence, and LP work.', 'Market databases, company graphs, and private-market intelligence. The raw material behind every investment memo.', 1, NULL, 1777215011764, 1777215011764), ('cat-3', 'research', 'Research', 'Secondary research, expert calls, and sector deep-dives — where Indian theses get pressure-tested before they reach IC.', '🔬', '/images/categories/research.jpg', 'Research is where a thesis lives or dies. Inside a fund, these tools power sector deep-dives, comp pulls, expert calls before IC, founder-claim verification, and the IC pre-read itself. The work used to be a junior analyst''s week — scrape filings, ping ex-operators, build a market map, write the memo. Deep-research agents now compress that to an afternoon, which means the bar for "did you actually look" has moved up, not down.

The Indian reality is harder than the Bay Area version. Expert networks are thin in fintech-ops, Tier-2 retail, BFSI middle-management, and most regulated sectors — the operator who actually ran the unit doesn''t take GLG calls. Half the source material lives in Hindi, Tamil, or trade press a US-trained model has never indexed. Most funds end up triangulating across two or three sources by job: paid sector reports for sizing, expert calls for verification, and AI-driven desk research for the long tail.', '[{"label":"India coverage and expert availability.","description":"Global panels miss Tier-2 consumer, BFSI ops, and regulated sectors. Insist on Indian experts and Indian sector depth before you sign."},{"label":"Expert credentials.","description":"Resume-grade titles aren''t operator experience. Verify the expert actually ran the unit you care about — before the call, not after."},{"label":"Fit-to-job.","description":"Buy for desk research, expert calls, or competitive intel — not all three. Tools that claim everything usually do nothing well."}]', NULL, '[]', '[]', '["data","ai","news","crm"]', 'Research Tools for VCs · Diligence Stack 2026', 'The research tools Indian VCs use for diligence: expert networks, sector intelligence, and primary-market research. AlphaSense, Redseer, Kavi, and more.', 'Primary and secondary research workbenches. Expert calls, sector scans, and the long read behind a short decision.', 2, NULL, 1777215011764, 1777215011764), ('cat-4', 'news', 'News', 'The daily broadsheet of Indian venture: feeds, paywalled scoops, and curated newsletters investors read before chai.', '📰', '/images/categories/news-resources.jpg', 'News tooling is a fund''s early-warning system: deal alerts before the term sheet hardens, sector signal that re-prices a thesis, founder back-channel monitoring (who''s hiring, who''s quietly moving), and ecosystem awareness so partners walk into Monday already aligned. The morning scan is not entertainment — it''s pipeline. Miss a story, miss a round.

In India, the global tech press is a trailing indicator. Inc42, Entrackr, YourStory, and Moneycontrol break funding rounds first; The Ken and The Morning Context own the longform paywalled angle that matters for diligence. Vernacular trade press surfaces Tier-2 stories Bangalore Twitter never sees. The real problem is signal-to-noise — twenty tabs, fifteen WhatsApp groups, and one missed Inc42 paragraph that would have flagged the down-round.', '[{"label":"India coverage depth.","description":"The Ken and Morning Context out-report TechCrunch on every Indian deal that matters. Budget two paid Indian subs before any global one."},{"label":"Speed vs analysis split.","description":"Entrackr and Inc42 break the round; Ken and Morning Context explain why it priced that way. Pick one of each, not three of either."},{"label":"Inbox vs app discipline.","description":"Match delivery format to how your team actually consumes — newsletters die in apps nobody opens, apps die in inboxes nobody filters."}]', '{"beginner":"Inc42, Entrackr, YourStory, VCCircle, Moneycontrol, Economic Times, Live Mint. The free India-scoop layer. If you''re not reading these daily, nothing else matters.","intermediate":"Add The Ken and The Morning Context for paid longform that turns headlines into thesis. Arc and The Generalist for global context.","advanced":"TechCrunch, Forbes, Entrepreneur India as the global context layer once the India base is dialled. Layer AI summarisation on top to collapse the firehose into a five-minute brief."}', '[{"label":"Confusing reading for sourcing.","description":"Headlines feel productive; they don''t fill a pipeline. News informs the call, it doesn''t replace it."},{"label":"Subscription bloat.","description":"Five paywalls and zero discipline equals five unread newsletters. Two well-read Indian paid subs beat the entire menu."}]', '[]', '["data","research","ai","crm"]', 'News Sources for VCs · Daily Reading List 2026', 'The news sites and newsletters Indian VCs actually read each morning. The Ken, The Generalist, Inc42, VCCircle, Morning Context — ranked and explained.', 'The daily broadsheet of venture. Feeds, aggregators, and newsletters investors read before the first coffee.', 3, NULL, 1777215011764, 1777215011764), ('cat-5', 'ai', 'AI', 'General-purpose AI copilots — the cognitive layer underneath every memo, model, and WhatsApp deal triage at an Indian fund.', '✨', NULL, 'AI tools have stopped being a budget line and become the substrate. Inside a 2026 fund, the first tab opened isn''t email — it''s a chat window. Inbound deck triage, memo skeletons, call summaries, market maps, thesis pressure-tests, LP update drafts, even reference-call prep all start in a copilot. The funds compounding fastest aren''t the ones with the cleverest prompts; they''re the ones who''ve moved firm context — playbook, ICP, portfolio, anti-portfolio — into reusable skills and shared assistants so every analyst inherits the partners'' brain.

The India reality is messier than the Twitter version. Most teams quietly run two assistants — ChatGPT for breadth, Claude for long diligence reads — on personal logins, expensed in INR. Founder decks arrive in Hinglish, Tamil-English, regional WhatsApp voice notes; reasoning quality on code-mixed input still varies sharply by model. Sensitive diligence — cap tables, founder backgrounds, MCA filings — demands enterprise plans where training is disabled and data residency is auditable.

The journey isn''t about which tool. Most funds use the same handful — Claude, ChatGPT, Perplexity, Gemini. It''s about how deeply you use them.', '[{"label":"Workspace integration.","description":"The assistant that wins is the one already inside Gmail, Slack, or Notion where your team spends 80% of the day. Everything else stays a tab."},{"label":"Team plan with shared context.","description":"Personal seats die when the analyst leaves. Team plans let you build skills and shared projects the whole firm inherits — and someone updates weekly."},{"label":"Enterprise privacy and data retention.","description":"Confirm training-off, audit logs, SSO, and a retention policy that matches your LP commitments before any cap table touches the model."},{"label":"Reliability and support.","description":"Even category leaders go down — Claude has had meaningful, repeated outages, and support response on consumer plans is uneven. Check the status page, support SLAs, and have a fallback model wired up."}]', '{"beginner":"Daily chat. Paid seats of Claude or ChatGPT for deck triage, memo skeletons, call summaries, market scans. Free tiers leak data — start paid.","intermediate":"Same models, deeper leverage. ChatGPT Projects and Custom GPTs, Claude with skills and shared assistants, Notion AI over your wiki, Perplexity for sourced research, Gemini if your fund lives in Google Workspace. The firm''s playbook starts living inside the tool.","advanced":"Claude Code, Codex, the API layer. Multi-tool routing — different models for different jobs based on token cost, latency, context window, security posture. Internal platforms for sourcing, screening, and memo automation. Manus for autonomous multi-step work; DeepSeek where INR-economics matter on high-volume API calls."}', '[{"label":"Personal accounts on firm data.","description":"Knowledge walks with the person. Skills, projects, and prompt libraries built on personal seats vanish when the analyst leaves — that''s pure technical debt. Team plans aren''t optional."},{"label":"Tool sprawl too early.","description":"Five assistants tested in parallel before one is dialled in usually leaves you with five half-used seats. Standardise on one; experiment with the rest only after the first is working."},{"label":"Clever prompts without team-wide skills.","description":"A partner''s good prompts in a personal chat don''t compound. Skills, projects, and shared assistants — owned by someone, updated weekly — do."}]', '[]', '["transcription","research","productivity","vibe-coding"]', 'AI Tools for VCs · Investor Copilots in 2026', 'The AI stack Indian VCs actually use: Claude, ChatGPT, Perplexity, Gemini. How to pick, how to set up Projects, and where AI breaks during diligence.', 'General-purpose copilots and assistants. The cognitive layer sitting under every other workflow on this page.', 4, NULL, 1777215011764, 1777215011764), ('cat-6', 'portfolio-management', 'Portfolio Management', 'Where the cap table stops being a spreadsheet — KPIs, quarterly letters, and valuation marks for what you already own.', '📊', '/images/categories/portfolio-management.jpg', 'Sourcing gets the headlines; portfolio management is what your LPs actually grade you on. For most Indian funds, post-investment ops still runs on a Google Sheet, a partner chasing founders on WhatsApp the week before IC, and an associate copy-pasting MIS decks at 2am before the LP call. SEBI AIF Category II reporting cadence — quarterly NAVs, audited annuals, drawdown notices — does not forgive that workflow at fund II and beyond.

The category splits into three shapes. Cap-table and fund admin tools (Carta, Eqvista) are the system of record for ownership and dilution. Portfolio monitoring specialists (Standard Metrics, Vestberry) automate KPI collection and normalise across the book. Integrated fund OS platforms (Taghash, Bunch) collapse dealflow, portfolio, and LP reporting into one contract.', '[{"label":"Founder-side friction.","description":"If your portfolio companies hate the input form, you''ll get late, dirty, or no data. Pick the tool founders complete in under ten minutes a quarter."},{"label":"SEBI AIF reporting fit.","description":"Quarterly unaudited NAVs, INR-denominated capital accounts, FEMA-aware foreign LP statements. Global-only tools force a parallel India workbook."},{"label":"Interoperability with CRM and cap-table source.","description":"Affinity or Attio plus Carta plus monitoring should behave like one system, not three."}]', '{"beginner":"Carta or local equivalent for the cap table, plus a disciplined quarterly KPI template in Google Sheets. Stop emailing founders for the same five numbers.","intermediate":"Add a monitoring layer — Standard Metrics, Vestberry — that pulls KPIs directly, flags drift, and generates the LP quarterly without manual consolidation. Most Indian funds with 20+ companies should live here.","advanced":"Integrated fund OS — Taghash, Bunch — where pipeline, ownership, KPIs, NAV, and LP comms share a graph, with AI on top doing portfolio anomaly detection and proactive value-creation prompts."}', '[{"label":"Buying a portfolio OS before you have a portfolio problem.","description":"Funds with under 15 companies almost always over-tool. A clean Sheet, a Carta seat, and a non-negotiable quarterly cadence beats a half-adopted platform."},{"label":"Treating monitoring as LP theatre, not value creation.","description":"The point of clean, comparable KPIs is that you spot drift two quarters early and act — intro, hire, bridge, hard conversation. If the data only ever surfaces in the LP letter, you bought the wrong category."}]', '[]', '["crm","admin-ops","data","communication"]', 'Portfolio Management for VCs · Top Tools 2026', 'The portfolio-monitoring and LP-reporting tools VCs use in 2026. Taghash, Standard Metrics, Carta, Vestberry — picked for Indian funds of every size.', 'Where a fund watches what it already owns. Metrics, KPIs, and quarterly letters for the companies on the cap table.', 5, NULL, 1777215011764, 1777215011764), ('cat-9', 'admin-ops', 'Admin & Ops', 'Fund administration, SEBI AIF compliance, capital calls, and the back-office scaffolding that lets an Indian VC firm actually run.', '⚙️', '/images/categories/infrastructure.jpg', 'The whole question of fund admin in India collapses into one decision: where does the fund live, and what regulator does it answer to? A SEBI-registered Cat I or Cat II AIF in Mumbai means quarterly compliance reports, custodian arrangements, valuation under SEBI norms, and audit cycles that look nothing like a Delaware LLC. A GIFT City IFSC fund layers on USD-denominated reporting, FATCA/CRS, and a different regulator (IFSCA). Pick the wrong tool for the wrong structure and you spend year two re-platforming instead of investing.

The Indian platform layer has matured. A sub-INR 100 Cr fund or syndicate-style vehicle can run end-to-end on AngelList India, LetsVenture, or Trica. Mid-sized AIFs typically split: an Indian platform or admin firm for SEBI, FEMA, and RoC, plus a cap-table and waterfall layer (Carta) for portfolio and carry tracking. Above that, institutional GPs move to traditional fund admins — Apex, IQ-EQ, Vistra — not because the platforms can''t handle scale, but because LPs at that ticket size expect a Big-4-audited admin name on the K-1 equivalent.', '[{"label":"Structure-native, not retrofitted.","description":"A tool built for Delaware C-corps will leak abstractions into every SEBI filing. Indian-built platforms understand contribution agreements, INR drawdown notices, and Form III out of the box."},{"label":"LP reporting that looks institutional.","description":"Capital account statements, IRR/DPI/TVPI, drawdown notices go to family offices and DFIs comparing you to global GPs. PDFs from a spreadsheet template stop scaling at fund II."},{"label":"Switching cost is the real lock-in.","description":"Migrating fund admin mid-vintage is brutal — historical NAVs, audit trails, LP records all have to come along. Pick for fund III, not fund I."}]', '{"beginner":"Single SPV or rolling vehicle. Pick one Indian platform — AngelList India, LetsVenture, or Trica — and live inside it.","intermediate":"Sub-INR 250 Cr Cat II AIF with a real CFO or ops lead. Stitch a platform plus Carta plus an external CA firm.","advanced":"Multi-fund, GIFT City plus domestic structure, institutional LPs. You''re now buying a fund admin relationship, not a SaaS product."}', '[{"label":"Treating GIFT City as a tax hack instead of an ops decision.","description":"The IFSCA regime is a different rulebook with different admin, audit, and reporting. Decide structure before tooling."},{"label":"Outsourcing compliance entirely to the platform.","description":"SEBI quarterlies, valuation policy, PPM updates — all still the GP''s liability. The platform automates the filing; it does not own the obligation."}]', '[]', '["portfolio-management","crm","automation","data"]', 'Fund Admin & Ops Tools for VCs · India 2026', 'The fund-admin, syndicate, and AIF-ops platforms Indian VCs rely on. AngelList, LetsVenture, Incentive, Carta — picked for SEBI-registered funds and angels.', 'Fund administration, compliance, and the operational scaffolding behind running a venture firm.', 6, NULL, 1777215011764, 1777215011764), ('cat-10', 'automation', 'Automation', 'Workflow glue for funds. No-code engines that wire CRM, inbox, and data room together — and where AI agents start replacing analyst grunt hours.', '🔁', NULL, 'Most Indian fund workflows have manual seams an analyst is paid to stitch: pitch landing in inbox, deck saved to Drive, founder pushed into CRM, sector-tagged, routed to the right partner, LinkedIn checked for hiring signal. Each step is small. Stack thirty deals a week and it eats a junior''s day. Automation tools collapse that into a flow that runs while you sleep — and the new generation of agent-native builders means the flow can now reason, not just route.

The Indian gravity to fight is the "arre, the analyst will just do it" reflex. People are cheap here, automation feels expensive, so funds delay building flows that would compound for years. Rule of thumb: if a task happens more than twice a week, automate it before you hire for it.', '[{"label":"Native connectors for your stack.","description":"Affinity, Attio, Notion, Gmail, Slack, Drive, plus India-local connectors like WhatsApp Business, Razorpay, Zoho. Missing one connector kills the whole flow."},{"label":"Branching and error handling.","description":"Real workflows fork and fail. Check retry logic, error notifications, run logs. Cheap tools skip this and you find out three weeks of deal data is missing."},{"label":"Agent-readiness.","description":"Does it expose an MCP server, webhook in/out, or LLM steps? The stack you pick today should plug into the agent layer you''ll add in 12 months."}]', '{"beginner":"Zapier. The default. Best app coverage in the world, including Indian-relevant ones — Razorpay, Zoho, WhatsApp Business. Use for the boring 80%: route emails, log forms, sync calendars. Ten reliable Zaps beats fifty broken ones.","intermediate":"Make for visual branching and multi-step logic, cheaper at volume. Or n8n self-hosted, open-source — the default for funds nervous about LP data on US SaaS.","advanced":"Lindy and Bardeen. AI-agent layer. Instead of \"if this then that,\" you brief an agent: watch these 40 LinkedIn profiles, alert me when anyone changes job, draft an intro in my voice. This is where analyst hours stop existing."}', '[{"label":"Building 50 workflows, maintaining zero.","description":"Automations rot — APIs change, tokens expire, edge cases break. Without a named owner, your \"automated fund\" silently turns back into a manual one."},{"label":"Automating the wrong layer.","description":"Funds wire up beautiful Zapier flows around a CRM nobody updates. Fix source-of-truth discipline first; automating chaos just produces faster chaos."}]', '[]', '["crm","productivity","data","admin-ops"]', 'Automation Tools for VCs · Zapier, Make, PhantomBuster', 'The no-code automation platforms VCs use to wire CRMs, inboxes, and data rooms together. Zapier, Make, PhantomBuster — compared for fund workflows in 2026.', 'Workflow glue. No-code engines that wire your CRM, inbox, and data room together without a developer.', 7, NULL, 1777215011764, 1777215011764), ('cat-11', 'communication', 'Communication', 'Where the partnership talks to itself and the outside world. WhatsApp runs founder threads, Slack runs the partnership.', '💬', '/images/categories/video-conferencing.jpg', 'In Indian VC, communication is bifurcated by audience and you don''t get to choose. WhatsApp owns every founder, co-investor, banker, and angel conversation that matters — pitches arrive there, term sheets get negotiated there, "quick check" intros happen there. Slack (or the equivalent) is what the partnership uses to talk to itself: deal channels, IC prep, weekly pipeline. The fund that pretends Slack can replace WhatsApp loses dealflow inside a quarter. The fund that lets WhatsApp eat the partnership loses institutional memory.

Video is a separate axis. First founder calls in Tier-2 and Tier-3 cities still hit bandwidth walls — your call tool needs to degrade gracefully, not just look pretty on a Mumbai fibre line. US LP updates are non-negotiably high-fidelity, scheduled, and recorded. Diligence rooms (data rooms, secure file exchange) belong in this category too, because access patterns — who saw the cap table, when, from which IP — are themselves the conversation in late-stage rounds.', '[{"label":"WhatsApp capture path.","description":"If the tool can''t get WhatsApp threads into your system of record without a human copy-paste, it''s a leak. Native WhatsApp Business API integration is the bar for any India-deployed fund."},{"label":"Graceful degradation on weak networks.","description":"Founder calls fail on the founder''s bandwidth, not yours. Audio-first fallback and dial-in numbers matter more than 4K."},{"label":"Access logs and retention controls.","description":"For diligence rooms and LP comms, you need to know who saw what, when — and prove it years later."}]', '{"beginner":"Pick one internal channel tool — Slack or Teams — and stop using email internally. Move founder convos out of personal WhatsApp into a fund-branded WhatsApp Business number so the next analyst can inherit the thread.","intermediate":"Wire WhatsApp into the CRM. Standardise video — Zoom or Google Meet — for institutional calls; stop letting partners pick by mood.","advanced":"Treat the partnership channel as the source of truth for IC decisions — every deal has a thread, every thread has a decision log. Diligence rooms (DocSend, Notion) gated, watermarked, and access-logged by default."}', '[{"label":"Letting personal WhatsApp own institutional relationships.","description":"When the partner leaves, the dealflow leaves with their phone. Fund-owned numbers and CRM sync are the fix — not a policy memo."}]', '[]', '["crm","mailing","productivity","transcription"]', 'Communication Tools for VCs · Slack, WhatsApp, Discord', 'How Indian VCs actually talk — with founders, with LPs, and with each other. WhatsApp, Slack, Discord, Telegram — picked for fund ops in 2026.', 'Where the partnership talks to itself and the outside world. Chat, video, and the rooms where diligence happens.', 8, NULL, 1777215011764, 1777215011764), ('cat-12', 'mailing', 'Mailing', 'Inbox infrastructure for funds. Founder threads, LP letters, deliverability — and the AI triage that turns 200 daily threads into 30 minutes of work.', '📧', '/images/categories/email.jpg', 'Email is where every VC''s day starts and ends. Term sheets get negotiated in threads. Founders judge response speed before they judge the term sheet. LPs read your name in a subject line before they open the memo. The quarterly letter is the single piece of writing investors actually finish — and the only writing the firm produces that lands in the inboxes that fund the next vehicle. Most Indian funds end up in inbox bankruptcy by Wednesday; the ones that don''t have moved off Gmail''s default surface.

Indian VC inboxes are dense, not high-volume. Founders WhatsApp first and email second, so what lands in your inbox is mostly warm intros, data rooms, and follow-ups — slower per thread, weightier per reply. US LPs read your update at 7am ET (your dinner time); Singapore LPs at 9am SGT (your morning) — schedule-send isn''t a feature, it''s table stakes. And Indian Gmail inboxes are saturated with promotional noise, so deliverability for LP letters matters more than design — a beautiful quarterly that lands in Promotions might as well not exist.', '[{"label":"Speed and keyboard depth.","description":"A partner reads 200+ threads a day. Mouse-driven UIs cost real hours; keyboard-first clients pay for themselves in week one."},{"label":"AI triage that fits your workflow.","description":"Bundles, summaries, and reply drafts done well save 30–40 minutes a morning. Done badly, they add a step."},{"label":"Smart-send and timezone awareness.","description":"Indian funds mailing US, UK, and Singapore LPs need the email to land at the recipient''s open-time, not yours. Without it, your update reads as the late-night blast it actually was."},{"label":"Calendar and CRM hooks.","description":"Native handoff to Cal.com, Calendly, Affinity, or Attio matters more than any AI feature. Friction here breaks first-meeting conversion."}]', '{"beginner":"Gmail or Outlook with keyboard shortcuts, labels, and saved replies. Free, universal, no lock-in. Get inbox hygiene right before paying for anything.","intermediate":"Shortwave or Notion Mail. AI triage, bundles, and team views once founder volume crosses 50 threads a day. Pick the one that already lives where your team works.","advanced":"Superhuman. Multiple inboxes (dealflow, portfolio, LP, ecosystem), read receipts on every founder reply, Smart Send to land at the recipient''s actual open-time, share-an-email-as-link to kill the dead \"FYI\" forward chain, cadences for follow-ups your team would otherwise lose. The cost is real; so is the leverage."}', '[{"label":"Buying AI features you''ll never configure.","description":"Most teams adopt 10% of the surface. Pilot with one partner for two weeks before a firm-wide rollout."},{"label":"Ignoring deliverability on LP letters.","description":"A quarterly sent from a fancy client into a saturated Indian inbox lands in Promotions. Warm the domain, plain-text it, test before send."},{"label":"One inbox for everything.","description":"Dealflow, portfolio, LP, and ecosystem in one undifferentiated stack guarantees the LP email you needed to surface gets buried under founder follow-ups. Split inboxes by purpose; triage by priority."}]', '[]', '["communication","productivity","calendar","crm"]', 'Email Tools for VCs · Superhuman, Shortwave, Notion Mail', 'The email clients Indian VCs use to triage inbound decks, send LP updates, and manage founder follow-ups. Superhuman, Shortwave, Notion Mail — compared.', 'Inbox infrastructure. From founder LP mail to quarterly newsletters, this is where correspondence is sent and filed.', 9, NULL, 1777215011764, 1777215011764), ('cat-13', 'calendar', 'Calendar', 'Booking, blocking, and defending time. Calendars built for funds juggling IST partner blocks, founder triage across cities, and 9pm LP calls.', '📅', '/images/categories/calendar.jpg', 'A VC''s calendar is the firm''s real org chart. It decides which founder gets ten minutes on Tuesday, which IC slot survives the week, and which LP gets a 9pm IST callback. Booking links route inbound founder triage off your inbox; dedicated calendar clients give partners keyboard speed across stacked days; AI on top now reads context, drafts agendas, and defends focus blocks. Calendar isn''t admin work — it''s the throughput control on partner attention, and often the difference between a fund that ships an IC every week and one that doesn''t.

India makes this harder. Most funds run a US, UK, or Singapore LP base, so every week has at least three timezones doing math against IST. Tools that show LPs an IST slot read amateur and cost you the second meeting. Founders ricochet across Bangalore, Mumbai, and Delhi; partner-meeting Mondays are sacred and routinely deflected; Friday afternoons disappear into dinner-prep traffic. The calendar tool that wins is the one that holds those constraints without you reminding it weekly.', '[{"label":"Firm-wide consistency.","description":"Every partner on the same booking link. Mixed setups confuse founders on warm intros and quietly kill conversion at the top of the funnel."},{"label":"Multi-timezone hygiene.","description":"IST, PST, GMT, and SGT in one week is the baseline. The tool should show LP slots in the LP''s timezone by default — not yours."},{"label":"CRM and notetaker hookup.","description":"Events should auto-log to the CRM and auto-trigger your transcription tool. If a partner has to copy-paste, the workflow is broken."},{"label":"AI agenda and prep.","description":"A 30-second pre-meeting brief — last touch, last memo, last commitment — turns a partner''s calendar into a working pipeline tool, not just a clock."}]', '{"beginner":"Cal.com. Open-source, generous free tier, one shared booking link across the partnership. Cheapest way to stop fragmenting your top-of-funnel.","intermediate":"Calendly for routed inbound — round-robin across partners, sector-specific links — plus Notion Calendar as the daily client that pulls pipeline, IC, portfolio, and personal events into one surface. Notion Calendar is, frankly, the most refined daily calendar available; if you already live in Notion, the integration is unfair.","advanced":"Vimcal. Keyboard-first, multi-timezone, EA-friendly. The calendar a heavy-schedule partner runs the day from. Layer AI on top for prep briefs, defended focus, and natural-language scheduling."}', '[{"label":"One link per partner.","description":"Personal Calendly pages fragment the firm. Founders get four links from four partners and pick the wrong one — or none."},{"label":"Calendar as inbox.","description":"Letting any founder self-book directly destroys deep-work blocks. Route inbound through an EA, a form, or a triage layer first."},{"label":"Manual timezone math.","description":"Every week a partner accidentally proposes 9am IST to a London LP. Fix it once, in the tool — don''t keep apologising."}]', '[]', '["mailing","productivity","communication","transcription"]', 'Calendar Tools for VCs · Vimcal, Calendly, Cal.com', 'The scheduling and booking tools Indian VCs rely on. Vimcal, Calendly, Cal.com, Notion Calendar — compared for partner meetings and founder calls.', 'Booking, blocking, and defending time. Tools that decide when the partnership meets and when the founder gets ten minutes.', 10, NULL, 1777215011764, 1777215011764), ('cat-14', 'transcription', 'Transcription', 'Notetakers and meeting recorders that turn every founder pitch, IC pre-read, and portfolio call into searchable institutional memory.', '📝', NULL, 'Transcription is the quietest leverage shift inside a fund this decade. Founder calls, IC pre-reads, expert interviews, portfolio updates, reference calls — all of it now lands as structured text within minutes. The associate scribbling notes is gone; the partner skimming a half-remembered conversation a quarter later is gone. Memos draft themselves from real transcripts, CRM contact records auto-update after every call, and the firm finally has a searchable spine of who-said-what — across years.

India adds friction the global playbook ignores. Early-stage founders, especially first-time ones, still flinch when a labelled bot joins the call — and most calls already have more bots than humans on them. Conversations run in code-mixed Hindi-English, sometimes Tamil, Marathi, or Kannada — accuracy collapses on weaker engines. Sensitive diligence demands clarity on retention and training-data settings; consumer plans almost always train on your audio.', '[{"label":"Auto-capture and summary quality.","description":"The whole point is to focus on the meeting, not the keyboard. Test summary quality on a real founder call — not a marketing video."},{"label":"Local capture vs visible bot.","description":"Most founder meetings already have more bots than humans. Local capture preserves chai-chat energy on first calls."},{"label":"Team plan with CRM sync.","description":"Personal plans don''t scale. Institutional memory only exists if every transcript lands on the contact record and every analyst can search across years of calls."},{"label":"Data privacy and training opt-out.","description":"Free tiers often train on your audio. Move regulated, M&A, and LP calls to team plans before — not after — an incident."}]', '{"beginner":"Granola. Local, no visible bot, two-minute setup. The simplest tool here that genuinely works — and the best way to start without changing meeting etiquette or asking permission on every cold call.","intermediate":"Fathom or Fireflies. Bot-based capture wired into the CRM (Affinity, Attio, Taghash) so summaries stop dying in folders. Move off personal plans to team plans here; institutional memory only works if everyone reads from the same archive.","advanced":"Notion Meetings if your fund is already inside the Notion ecosystem — the most comprehensive option, the transcript lands next to the thesis, and the integration with the rest of your wiki is unmatched. Or Circleback or Otter for firm-wide automations and a searchable archive across years of calls."}', '[{"label":"Personal plans for firm-critical calls.","description":"Transcripts are the institutional spine. If they live in one analyst''s account, the spine snaps when they leave."},{"label":"Bot-clutter on first pitches.","description":"Three notetakers introducing themselves before a founder finishes \"Hi\" is now a real meeting reality. Default to local capture for cold calls."},{"label":"Free tiers on sensitive deals.","description":"Training-on-your-audio is the default on consumer plans. Check before, not after."}]', '[]', '["ai","communication","crm","productivity"]', 'Transcription Tools for VCs · Granola, Fathom, Fireflies', 'The AI meeting notetakers Indian VCs use in 2026. Granola, Fathom, Fireflies, Otter — compared for founder calls, IC notes, and diligence interviews.', 'Meeting recorders and note-takers. Every call, pitch, and partner meeting turned into searchable text.', 11, NULL, 1777215011764, 1777215011764), ('cat-15', 'voice-to-text', 'Voice to Text', 'Dictation tools that turn cab-ride monologues, Hinglish voice notes, and between-meeting thoughts into clean CRM-ready text.', '🎙️', NULL, 'Voice-to-text has quietly become one of the highest-leverage unlocks in a VC''s stack. The work is verbal: founder calls, partner debates, IC pitches, hallway chatter. Typing is the bottleneck. With modern dictation, you push a hotkey in the back of an Uber and a 400-word Affinity update lands clean. You triage WhatsApp founder threads at 3x typing speed. You prompt Claude in full paragraphs instead of tortured fragments. You file IC memos before reaching the office. Once your brain rewires to it, there''s no going back.

India makes this harder than the demo videos suggest. Most associates code-mix mid-sentence — the ARR ka trajectory looks solid but burn thoda zyada hai — and weak engines collapse the moment Hinglish appears. Regional language dictation is still mostly a promise, not a product. Founder voice notes arrive in Hindi, Tamil, Marathi, often layered with English jargon. The right engine compounds; the wrong one wastes you a week before you give up.', '[{"label":"Hinglish and code-mix accuracy.","description":"Test with your real voice, not a clean script — code-mixed sentences are where most engines silently fail."},{"label":"System-wide hotkey.","description":"Must dictate into Affinity, Slack, Gmail, Notion, and Claude without context-switching or copy-paste detours."},{"label":"Privacy posture.","description":"Confirm whether audio processes locally or hits a cloud — regulated deals and term-sheet drafts often need on-device only."},{"label":"Post-processing quality.","description":"The gap between raw transcript and publishable draft is huge. Demand AI cleanup that removes filler and respects your voice."}]', '{"beginner":"Wispr Flow. Default starting point. Clean dictation across every app, handles Indian English well, two-minute setup. Most VCs who stick with voice-to-text started here and stayed.","intermediate":"Aqua Voice or Willow Voice. Hotkey dictation with style-matching and name accuracy for portfolio-heavy workflows.","advanced":"Superwhisper. Offline mode and configurable LLM post-processing for funds that need local processing on regulated diligence or term-sheet drafts."}', '[{"label":"Buying on demo, not daily use.","description":"Vendor demos use studio audio; your real test is a noisy cab with two languages and a weak signal."},{"label":"Ignoring name and term accuracy.","description":"Indian founder names, fund acronyms, and sector jargon get mangled. Check custom-dictionary support before committing."},{"label":"Cloud transcription on sensitive notes.","description":"Sensitive IC notes and founder commitments shouldn''t be uploaded blindly. Default to local mode where the workflow allows."}]', '[]', '["ai","transcription","productivity","crm"]', 'Voice to Text Tools for VCs · Wispr Flow, Superwhisper', 'The dictation tools Indian VCs use between meetings. Wispr Flow, Superwhisper, Aqua Voice, Willow — compared for founder notes, CRM entries, and quick memos.', 'Dictation for the investor on the move. Turn voice memos between meetings into memos in the CRM.', 12, NULL, 1777215011764, 1777215011764), ('cat-16', 'productivity', 'Productivity', 'The fund''s second brain — wikis, docs, and dealflow boards where every thesis, IC pre-read, and portfolio note actually lives.', '🗂️', '/images/categories/project-management.jpg', 'Productivity tools are the connective tissue of a fund. The wiki holds your sector theses; databases run dealflow; pages carry IC pre-reads, post-mortems, and portfolio updates; templates onboard the next analyst. When this layer is sharp, founders feel a fund that remembers them; when it''s sloppy, the same diligence question gets asked three times across two partners and one associate.

The Indian reality is messy. Most funds straddle Google Docs for speed, a half-built Notion wiki for "real" knowledge, and Sheets for everything numerical — Coda and Confluence sit on the edges. The serious shift in the last 18 months is AI inside the wiki: Notion AI run over a fund''s own docs and dealflow turns the wiki into a queryable second brain. Notion is now the closest thing to an Apple-style ecosystem in this layer — once you''re inside it, the integrations compound and the cost of leaving rises every quarter. Outside it, the learning curve is real and it can feel rigid. Pick the side and commit; the worst outcome is two half-built wikis.', '[{"label":"Adoption over features.","description":"The best stack is the one your associates actually open on Monday. Pick the platform your team already lives in, not the one that demos best."},{"label":"Docs vs database fit.","description":"Decide whether you primarily write narrative (Notion wins) or query relational data (Airtable, Coda win). Most Indian funds need both — pick a primary, integrate the other."},{"label":"Native AI surface.","description":"Memo drafting, meeting-note ingestion, and Q&A over your wiki should happen inside the tool, not via copy-paste. Test the AI on your own thesis pages before paying."}]', '{"beginner":"Google Sheets and Docs. Lowest-friction starting point. Every fund starts here before pretending otherwise.","intermediate":"Notion as the firm wiki and dealflow CRM, with Sheets kept for modelling. One source of truth, AI-assisted memo drafting inside the doc. Notion AI is genuinely underestimated — if your data lives there, \"every founder we met in fintech last quarter with ARR above ₹5 Cr\" is a five-second query.","advanced":"Airtable or Coda for relational dealflow, automations, and portfolio dashboards once views, roll-ups, and integrations outgrow Notion''s database layer. Layer AI agents on top for memo drafting, dealflow tagging, and portfolio anomaly detection."}', '[{"label":"Three half-built wikis.","description":"Notion, Drive, and a forgotten Confluence all hold stale theses. Pick one home, migrate hard, sunset the rest."},{"label":"Database sprawl on day one.","description":"Funds copy a 14-database template and fill none of it. Start with dealflow plus one thesis page; expand only when usage forces it."},{"label":"No offboarding ritual.","description":"Analyst leaves, their Loom links and private pages go with them. Mandate firm-owned workspaces and a written handover before the laptop is returned."}]', '[]', '["communication","mailing","automation","crm"]', 'Productivity Tools for VCs · Notion, Coda, Google Sheets', 'The docs, wikis, and task boards that run Indian venture firms. Notion, Coda, Google Sheets — compared for IC memos, portfolio tracking, and firm ops.', 'Docs, wikis, and task boards. The second brain where theses, diligence, and portfolio notes all live.', 13, NULL, 1777215011764, 1777215011764), ('cat-17', 'vibe-coding', 'Vibe Coding', 'Plain-English app builders for non-engineers. Ship a diligence form, LP dashboard, or sector map by EOD.', '🛠️', '/images/categories/platform.jpg', 'Vibe coding has collapsed the gap between "I need a small tool" and "I have a small tool." For an Indian fund without an in-house engineer, that''s the difference between a half-finished Notion doc and an actual login-gated diligence portal an analyst spun up before the IC meeting. The natural use cases are well-defined and unsexy: founder-intake forms, sector landscape maps, internal scoring dashboards, micro-sites for a thesis essay, an LP-only data room, the fund website itself.', '[{"label":"Output quality on your actual workflow.","description":"Demo videos lie. Rebuild the same internal form in three tools and compare what breaks on iteration two."},{"label":"Code export and backend portability.","description":"If the tool locks your data and code inside its own runtime, you''ve built a hostage, not an asset. Prefer tools that hand you a real Git repo."},{"label":"Iteration speed.","description":"The magic isn''t the first generation — it''s prompt-edit-redeploy in under 30 seconds. Slow loops kill the whole point."}]', '{"beginner":"A single-screen internal tool — deal tracker, intern application form — with no auth and no database. Lovable or Bolt chat-first; v0 if you live in Vercel and Next.js.","intermediate":"A multi-page app with Supabase for storage, Clerk or built-in auth, and a custom domain. The level where a principal can ship a portfolio founder portal.","advanced":"Export code to GitHub, wire CI, layer Replit Agent or Claude Code on top to maintain it long-term. Most fund teams should live at Beginner-to-Intermediate forever — past that, hire a contractor."}', '[{"label":"Treating the prototype as the product.","description":"A vibe-coded LP portal that handles ten logins is a demo, not infrastructure. Anything touching portfolio data, capital calls, or PII needs an engineer reviewing the auth and database layer before it goes live."},{"label":"Skipping the export step.","description":"Teams build six months of internal tooling inside a single platform, then discover the export is half-broken or paywalled. Pull the code to GitHub on day one."}]', '[]', '["ai","productivity","automation","browser"]', 'Vibe Coding Tools for VCs · Lovable, Bolt, Replit', 'The AI-native builders Indian VCs use to prototype landing pages, dashboards, and diligence tools without engineers. Lovable, Bolt, Replit, Emergent.', 'AI-native builders for non-engineers. Prototype a landing page, a dashboard, or a diligence tool before lunch.', 14, NULL, 1777215011764, 1777215011764), ('cat-18', 'browser', 'Browser', 'The window to the work. Investor-grade browsers with tabs, workspaces, and AI built into the address bar.', '🌐', NULL, 'The browser is where a VC actually spends the day — CRM, Gmail, Notion, portfolio dashboards, decks, and forty open tabs at any moment. After a decade of Chrome being the only answer, AI has made the layer interesting again: the browser can now read the page, summarise it, fill it, and act on it, not just render it.

The split is simple. Comet and Atlas treat AI as the primary interface, with the address bar acting as a question-and-action surface over whatever you''re looking at. Arc rethinks organisation around Spaces and profiles for people who live in tab chaos. Brave leans on default privacy. Chrome remains the universal fallback because shared screens, LP portals, and enterprise tools assume it. Most investors end up running two browsers — one personal daily driver, Chrome for everything external.', '[{"label":"AI integration depth.","description":"Whether the AI is genuinely embedded in the address bar and sidebar (Comet, Atlas) or bolted on as a chat panel. The first changes how you work; the second is just a shortcut to ChatGPT."},{"label":"Tab and workspace management.","description":"At 40+ tabs a day, Arc-style Spaces and profiles are the difference between a working browser and visual noise."},{"label":"Shared-screen and enterprise reliability.","description":"Chrome compatibility is non-negotiable for demos, Zoom webinars, and LP portals. Whatever you pick as primary, Chrome stays installed."}]', NULL, '[{"label":"Treating the AI browser as your only browser.","description":"Agentic browsers are still early — sessions break, extensions misbehave, some enterprise flows silently fail. Run the AI browser for personal work, keep Chrome for anything load-bearing."}]', '[]', '["ai","productivity","research","news"]', 'Browsers for VCs · Arc, Comet, Atlas, Chrome in 2026', 'The browsers Indian VCs use to run dealflow, diligence, and research. Arc, Comet, Atlas, Chrome, Brave — compared for tabs, AI, and investor workflows.', 'The window to the work. Investor-grade browsers with tabs, workspaces, and AI built into the address bar.', 15, NULL, 1777215011764, 1777215011764), ('cat-19', 'other-tools', 'Other Tools', 'The catch-all shelf. Design files, storage, forms, shortcuts, and utilities that don''t fit a focused category.', '🔧', '/images/categories/other-tools.jpg', 'This is a catch-all by design. Tools here span unrelated jobs — building a deck visual in Canva or Gamma, capturing a form response in Tally or Typeform, hosting an event in Luma, automating a desktop shortcut in Raycast, storing a fund deck in DocSend. There''s no shared workflow that binds them and no single buyer profile to optimise for. Most are picked up opportunistically when a specific need surfaces, kept if they earn their keep, and dropped without ceremony when they don''t.

Treat this category as a reference shelf rather than a stack to assemble. Each tool stands on its own merits for the narrow job it does. If a tool here matters to your workflow, it usually matters a lot for one specific task and not at all for the rest of the week.', '[{"label":"Single-job clarity.","description":"The tool should do one thing obviously well. Catch-all utilities that try to expand into adjacent categories tend to underperform the focused incumbents."},{"label":"Low switching cost.","description":"These sit at the edges of the workflow. Anything that locks in data, contacts, or assets deserves extra scrutiny before adoption."}]', NULL, '[{"label":"Stack creep.","description":"Easy to accumulate five overlapping utilities (three form tools, two design tools) because each was added for a one-off need. Audit this shelf periodically and consolidate where workflows have drifted into overlap."}]', '[]', '["productivity","admin-ops","browser","communication"]', NULL, NULL, NULL, 16, NULL, 1777215011764, 1777215011764) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, icon = excluded.icon, image_url = excluded.image_url, intro = excluded.intro, buying_criteria = excluded.buying_criteria, journey = excluded.journey, pitfalls = excluded.pitfalls, reading_list = excluded.reading_list, related_slugs = excluded.related_slugs, seo_title = excluded.seo_title, seo_description = excluded.seo_description, hero_angle = excluded.hero_angle, sort_order = excluded.sort_order, archived_at = excluded.archived_at, updated_at = excluded.updated_at;

-- Tools
INSERT INTO tools (id, slug, name, description, short_desc, use_cases, key_features, website_url, logo_url, pricing_model, is_featured, featured_order, category_id, extra_category_slugs, archived_at, created_at, updated_at) VALUES ('t-1', 'affinity', 'Affinity', 'Affinity is a relationship-intelligence CRM built for private markets. It auto-captures the network graph by reading Gmail, Outlook, and calendar activity in the background, so pipeline stays current without manual logging. It scores relationship strength and surfaces the warmest path to any contact. Widely used by VC firms to manage dealflow and find intros to founders.', 'Relationship-intelligence CRM that reads your inbox to map dealflow', '["Track dealflow from first meeting to term sheet without manual CRM entry","Find the warmest internal path to a founder before sending a cold email"]', '["Auto-syncs contacts and activity from Gmail, Outlook, and calendar","Relationship-strength scoring and warm-path mapping across the firm","Pipeline analytics with deal velocity and team reports"]', 'https://affinity.co', 'https://www.google.com/s2/favicons?domain=affinity.co&sz=128', 'PAID', 0, NULL, 'cat-1', NULL, NULL, 1777215011764, 1777215011764), ('t-2', 'airtable', 'Airtable', 'Airtable is a relational database with a spreadsheet-like interface, plus views, forms, and automations on top of every table. Non-technical users build custom trackers without writing SQL, and records connect across tables like a lightweight app. Widely used by VC firms as a lightweight dealflow tracker, portfolio database, or LP list before graduating to a dedicated CRM.', 'Flexible relational database that behaves like a spreadsheet', '["Build a dealflow tracker with custom stages, owners, and scoring in an afternoon","Keep a shared portfolio database with founder contacts, board dates, and KPIs"]', '["Relational database with views, forms, and automations on every table","Spreadsheet-like interface for non-technical users to build trackers","Connected records and lightweight app-builder workflows"]', 'https://airtable.com', 'https://www.google.com/s2/favicons?domain=airtable.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', '["productivity"]', NULL, 1777215011764, 1777215011764), ('t-3', 'asana', 'Asana', 'Asana is a work management platform that organises projects, tasks, and goals across a team in shared views like lists, boards, timelines, and Gantt. Automations and AI teammates handle status updates, request intake, and routine follow-ups. Used by VC firms to run platform team projects, fundraising workstreams, and portfolio support programs with clear ownership and deadlines.', 'Work management platform for tracking projects, tasks, and goals', '["Run a fundraising workstream with LP outreach tracked by stage and owner","Coordinate portfolio support programs across platform, talent, and marketing teams with clear ownership and deadlines"]', '["Lists, boards, timelines, and Gantt views for shared projects","Automations and AI teammates for status updates and request intake","Goals, milestones, and ownership tracking across teams"]', 'https://asana.com', 'https://www.google.com/s2/favicons?domain=asana.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', NULL, NULL, 1777215011764, 1777215011764), ('t-4', 'attio', 'Attio', 'Attio is an AI-native CRM built around a fully customisable data model, with email and calendar sync, contact enrichment, and semantic search across meetings and threads. No-code automations and reports make it adaptable to any pipeline shape. Increasingly used by VC firms as a lighter, more modern alternative to Affinity for tracking dealflow, relationships, and portfolio contacts.', 'AI-native CRM with a flexible data model and semantic search', '["Shape a custom dealflow pipeline with investor-specific fields, stages, and automated enrichment on every new record","Search every past meeting and email for context on a founder before a call"]', '["Fully customisable data model with email and calendar sync","AI lead scoring and no-code workflow automations","Semantic search across past meetings and threads"]', 'https://attio.com', 'https://www.google.com/s2/favicons?domain=attio.com&sz=128', 'PAID', 1, NULL, 'cat-1', NULL, NULL, 1777215011764, 1777215011764), ('t-5', 'clay', 'Clay', 'Clay pulls from 150+ data providers in a waterfall to enrich any list of companies or people, then layers AI research agents and buying-intent signals on top. Teams build audiences, write outreach, and push to CRMs from one spreadsheet-like surface. Used by VC firms to build founder lists, enrich dealflow with funding and headcount data, and automate sourcing outreach.', 'Data enrichment and AI research for targeted outbound at scale', '["Build a ranked list of seed-stage founders by role, headcount growth, and recent funding","Enrich inbound deal submissions with team backgrounds, competitive landscape, and funding history before they reach an investor"]', '["150+ data providers in a waterfall for company and people enrichment","AI research agents and buying-intent signals on every record","Pushes enriched lists to CRMs and outreach tools"]', 'https://clay.com', 'https://www.google.com/s2/favicons?domain=clay.com&sz=128', 'PAID', 0, NULL, 'cat-1', NULL, NULL, 1777215011764, 1777215011764), ('t-6', 'evertrace', 'EverTrace', 'A founder-detection engine that flags builders before they appear in conventional startup databases. It watches signals across LinkedIn, GitHub, X co-founder search posts, trade registries, domain registrations, patents, research papers, and hackathon wins, then routes matches into Affinity, Attio, HubSpot, or Salesforce. Used by early-stage VCs to reach stealth founders weeks or months ahead of competing funds.', 'Stealth-founder detection from LinkedIn, GitHub, X, and registry signals', '["Surface stealth founders from LinkedIn, GitHub, and X signals before they list a company","Pipe real-time incorporation and domain alerts into Affinity or Attio for same-day outreach"]', '["Signal aggregation across LinkedIn, GitHub, X, patents, and registries","Real-time alerts on stealth-founder activity","Pushes matches into Affinity, Attio, HubSpot, or Salesforce"]', 'https://evertrace.ai', 'https://www.google.com/s2/favicons?domain=evertrace.ai&sz=128', 'PAID', 1, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-7', 'folk', 'Folk', 'Folk is a modern, lightweight CRM focused on relationship management rather than heavy sales pipeline. Its folkX browser extension captures contacts from LinkedIn, Gmail, and Outlook in one click, and AI assistants handle follow-ups, recaps, and enrichment. Used by smaller VC firms, angels, and scouts to track founder conversations and investor networks without the overhead of an enterprise CRM.', 'Lightweight CRM that pulls contacts from LinkedIn, Gmail, and WhatsApp', '["Capture founders and co-investors from LinkedIn into a shared CRM in seconds","Run personalised investor updates or founder outreach off a segmented contact list enriched from LinkedIn"]', '["folkX extension captures contacts from LinkedIn, Gmail, Outlook in one click","AI follow-up reminders and conversation recaps","Auto-generated research briefs on companies and contacts"]', 'https://folk.app', 'https://www.google.com/s2/favicons?domain=folk.app&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', NULL, NULL, 1777215011764, 1777215011764), ('t-8', 'hubspot', 'HubSpot', 'HubSpot bundles CRM, marketing automation, sales pipeline, service desk, and content tools into one customer platform, with Breeze AI agents for prospecting, support, and data cleanup on top. Strongest on the inbound-and-outreach side where most tools stop at CRM. Used by VC firms that run heavy content, newsletter, or LP marketing motions and want attribution back to the source.', 'Full CRM and marketing suite for firms that run outbound and content', '["Run LP and founder newsletters with full open, click, and attribution tracking","Manage inbound deal submissions through a standard CRM pipeline with automated routing"]', '["CRM, marketing automation, sales pipeline, service desk, and content hub","Breeze AI agents for prospecting, support, and data cleanup","Full attribution from first touch to closed-won"]', 'https://hubspot.com', 'https://www.google.com/s2/favicons?domain=hubspot.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', NULL, NULL, 1777215011764, 1777215011764), ('t-9', 'notion', 'Notion', 'Notion is the simplest place for a VC firm to begin: deal pipeline, portfolio tracking, DD data rooms, and the firm wiki all sit on one flexible surface of databases, docs, and AI agents. Recent launches add Notion Mail, Notion Calendar, and Notion Meetings, an AI meeting note-taker in the Granola style. For heavyweight enterprise CRM and LP automation, firms eventually graduate to dedicated tools.', 'AI workspace combining docs, databases, and agents in one surface', '["Deal pipeline — capture every founder thread, stage, and IC decision in custom databases linked to memo pages and meeting notes","Portfolio tracking — maintain one dashboard per portfolio company with KPIs, board notes, financial updates, and milestone history","DD data room — build structured research databases for market scans, reference calls, and competitor maps, all queryable via AI search","Light CRM — store LP and investor contacts, founder notes, and fundraising context as a simple starter before a dedicated tool"]', '["Custom databases, docs, and wikis on one flexible workspace","AI agents that search, summarise, and answer questions across pages","Notion Mail, Calendar, and Meetings — Granola-style AI note-taker built in"]', 'https://notion.so', 'https://www.google.com/s2/favicons?domain=notion.so&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', '["productivity","transcription"]', NULL, 1777215011764, 1777215011764), ('t-11', 'streak', 'Streak', 'Streak turns Gmail itself into a CRM, with pipelines, stages, and shared deal views rendered alongside the inbox. Email tracking, mail merge, and AI-powered columns automate logging and follow-ups without forcing a context switch. Popular with solo GPs and smaller VC firms who already run dealflow and LP conversations out of Gmail and want a CRM layer without leaving it.', 'CRM built directly inside Gmail for teams that live in the inbox', '["Track every founder email thread against a deal stage without leaving Gmail","Send personalised LP updates via mail merge with per-recipient open and click tracking directly from Gmail"]', '["Gmail-native CRM with pipelines, stages, and shared deal views","Email tracking, mail merge, and AI-powered columns","No context switch — everything renders inside the inbox"]', 'https://streak.com', 'https://www.google.com/s2/favicons?domain=streak.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', NULL, NULL, 1777215011764, 1777215011764), ('t-12', 'taghash', 'Taghash', 'Taghash is an integrated fund operating system that stitches dealflow, portfolio tracking, fund accounting, and LP reporting into one platform. Deals pull in from email, WhatsApp, and forms, while the portfolio module handles cap tables, valuations, and IRR, DPI, and MOIC metrics. Popular with Indian VC firms that want a single system instead of stitching five tools together.', 'All-in-one fund operating system covering dealflow, portfolio, and LPs', '["Consolidate dealflow from WhatsApp, email, and web forms into one triage queue","Generate quarterly LP reports with IRR, DPI, and MOIC directly from portfolio data"]', '["Dealflow inbox pulling from email, WhatsApp, and web forms","Portfolio MIS with cap tables, valuations, and IRR/DPI/MOIC tracking","Branded LP dashboards with capital calls and quarterly reports"]', 'https://taghash.io', 'https://www.google.com/s2/favicons?domain=taghash.io&sz=128', 'PAID', 1, NULL, 'cat-1', '["portfolio-management"]', NULL, 1777215011764, 1777215011764), ('t-13', 'cb-insights', 'CB Insights', 'A private-market intelligence platform covering 11 million companies and 1,600+ markets, with funding histories, hiring patterns, and Mosaic health scores. Strategy maps visualise competitive activity, and AI agents generate target lists, scouting reports, and memos. Used by VC and corporate venture teams to size emerging categories, track category leaders, and build diligence context before a first call.', 'Predictive intelligence on private companies, markets, and competitive activity', '["Build a market map of an emerging sector with funding, hiring, and Mosaic health scores","Pull comparable deals and category benchmarks to frame an investment committee memo"]', '["Mosaic predictive health scores on 11M+ companies","ChatCBI AI agent for target lists, scouting reports, and memos","Strategy maps across 1,600+ tech markets"]', 'https://cbinsights.com', 'https://www.google.com/s2/favicons?domain=cbinsights.com&sz=128', 'ENTERPRISE', 1, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-14', 'crunchbase', 'Crunchbase', 'The widely referenced private-market database, tracking funding rounds, founders, acquirers, and exits across global startups. Predictive signals flag companies likely to raise next, and the Pro tier exposes advanced filters, saved searches, and API access. Used by VCs for quick founder lookups, competitive scans, round timing, and as the baseline source for pipeline enrichment in CRMs like Affinity and Attio.', 'Public-facing private market database for funding rounds, companies, and exits', '["Check a founder''s prior funding history and co-investors before a first partner meeting","Filter by sector, stage, and last-round date to build a weekly outreach list"]', '["Funding round tracking with predictive likely-to-raise signals","Advanced filters, saved searches, and API access on Pro tier","Baseline enrichment source for CRMs like Affinity and Attio"]', 'https://crunchbase.com', 'https://www.google.com/s2/favicons?domain=crunchbase.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-15', 'harmonic', 'Harmonic', 'A discovery platform covering 30 million companies and 190 million people, tuned for catching startups at formation. Filters span funding, headcount, and growth metrics; the Scout agent takes natural-language briefs and returns research reports and market maps. Network mapping syncs email, calendar, and LinkedIn so VCs can spot warm intro paths and talent movement the moment a founder goes independent.', 'Early-stage startup and founder discovery engine with AI research agents', '["Track senior operators leaving top companies and trigger alerts when they start a new entity","Generate a Scout market map on an emerging thesis and auto-draft outreach to matching founders"]', '["30M companies and 190M people, tuned for catching startups at formation","Scout AI agent for natural-language briefs, research reports, and market maps","Network mapping over email, calendar, and LinkedIn for warm-intro paths"]', 'https://harmonic.ai', 'https://www.google.com/s2/favicons?domain=harmonic.ai&sz=128', 'PAID', 1, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-16', 'inc42-data-labs', 'Inc42 Data Labs', 'Inc42''s intelligence arm covers 75,000+ Indian startups, 3,000+ investors, and 20,000+ funding rounds, blending Inc42 reporting with MCA filings and 200+ proprietary feeds. Signal Feed pushes funding, regulatory, and talent alerts over email and WhatsApp within 24 hours. Used by India-focused VCs to build sector theses, track competitors, and export company snapshots straight into investment memos.', 'India startup intelligence platform with MCA data, signals, and company profiles', '["Track MCA filings and valuation trajectories of shortlisted Indian startups across a sector thesis","Subscribe to Signal Feed alerts on funding rounds and talent moves for weekly pipeline review"]', '["75,000+ Indian startups, 3,000+ investors, and 20,000+ funding rounds","MCA filings and 200+ proprietary feeds blended with Inc42 reporting","Signal Feed alerts pushed via email and WhatsApp within 24 hours"]', 'https://inc42.com', 'https://www.google.com/s2/favicons?domain=inc42.com&sz=128', 'PAID', 0, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-17', 'linkedin-sales-nav', 'LinkedIn Sales Nav', 'LinkedIn''s premium sourcing surface, with fifty-plus filters across function, seniority, tenure, and geography over a billion profiles. InMail credits unlock direct messaging, TeamLink surfaces warm paths through colleague networks, and Account and Lead IQ generate AI briefings on prospects. Used by VCs to build founder longlists, map portfolio hiring targets, and identify the shortest intro path before cold outreach.', 'LinkedIn''s advanced search, InMail, and warm-intro engine over a billion users', '["Build a filtered list of ex-FAANG founders in a target sector and trigger TeamLink warm intros","Map a portfolio company''s hiring targets and draft Account IQ briefs before outreach"]', '["50+ filters across function, seniority, tenure, and geography on 1B+ profiles","TeamLink warm-path discovery through colleague networks","Account IQ and Lead IQ AI briefings on every prospect"]', 'https://linkedin.com', 'https://www.google.com/s2/favicons?domain=linkedin.com&sz=128', 'PAID', 0, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-18', 'pitchbook', 'PitchBook', 'The institutional reference for private-market data, with deep coverage of VC, PE, M&A, and public markets across companies, funds, and LPs. Profiles carry round-by-round cap tables, valuations, comparables, and fund-level IRR benchmarks. Used by VC firms for competitive benchmarking, diligence on co-investors, LP research ahead of fundraising, and pulling comparable-deal valuations into investment memos.', 'Institutional private-market data spanning VC, PE, M&A, and fund performance', '["Pull round history, cap table, and valuation comps for a target before an IC memo","Benchmark a fund''s pace and TVPI against peer vintages during LP fundraising prep"]', '["Round-by-round cap tables, valuations, and comparables","Fund-level IRR, TVPI, and DPI benchmarks","VC, PE, M&A, and public-market coverage in one platform"]', 'https://pitchbook.com', 'https://www.google.com/s2/favicons?domain=pitchbook.com&sz=128', 'ENTERPRISE', 1, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-19', 'preqin', 'Preqin', 'Preqin Pro covers eight alternative-asset classes, including VC, PE, hedge funds, private debt, real estate, and infrastructure. Data runs across funds, managers, deals, and institutional LPs, with benchmarks for IRR, TVPI, and fund terms. Used by GPs to identify and prioritise LPs for the next fundraise, and by LPs to screen managers, run due diligence, and benchmark returns against peer vintages.', 'Alternative-assets data for fund performance, LP mapping, and manager selection', '["Build a ranked LP target list by asset-class appetite and historic ticket size before fundraising","Benchmark a fund''s IRR and DPI against peer vintage and geography during LP reporting"]', '["Coverage across eight alternative-asset classes (VC, PE, hedge, debt, real estate)","Institutional LP profiles and ticket-size data for fundraising","IRR, TVPI, and fund-terms benchmarks across vintages"]', 'https://preqin.com', 'https://www.google.com/s2/favicons?domain=preqin.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-20', 'private-circle', 'Private Circle', 'An India-focused research database on 2.6 million unlisted companies, built from MCA filings, triangulated financials, and compliance records. Screeners cover income statements, balance sheets, valuations, cap tables, and legal cases, with web and app-traffic signals layered in. Used by VC, PE, and IB teams for diligence on Indian targets, competitor benchmarking, and screening for founders with strong underlying financial signals.', 'India private-company intelligence built on MCA filings and triangulated data', '["Pull three-year financials and shareholding from MCA filings for diligence on an Indian target","Screen Indian companies by revenue, margin, and cap-table shape to build a thematic longlist"]', '["2.6M unlisted Indian companies from MCA filings and triangulated data","Screeners across financials, valuations, cap tables, and legal cases","Web and app-traffic signals layered onto compliance records"]', 'https://privatecircle.co', 'https://www.google.com/s2/favicons?domain=privatecircle.co&sz=128', 'PAID', 0, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-22', 'sanchi-connect', 'Sanchi Connect', 'India''s dedicated deeptech enablement network, connecting startups working on AI, robotics, quantum, biotech, and semiconductors with 470+ investors, 150+ mentors, and 50+ corporate partners. SanchiSaaS handles incubation workflows, while PowerPitch and Live Pitch run video pitches and application reviews. Used by deeptech VCs for curated dealflow and by corporates for POC partnerships with vetted Indian research-led teams.', 'India deeptech network linking founders with investors, mentors, and corporates', '["Source pre-vetted Indian deeptech startups by sector and pitch stage for a quarterly review","Run corporate innovation POCs with deeptech founders matched through the Sanchi network"]', '["Curated network of 470+ investors, 150+ mentors, and 50+ corporate partners for deeptech","PowerPitch and Live Pitch for video applications and pitch reviews","SanchiSaaS workflows for incubation programmes and POC matching"]', 'https://sanchiconnect.com', 'https://www.google.com/s2/favicons?domain=sanchiconnect.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-23', 'tracxn', 'Tracxn', 'A Bengaluru-founded global startup database with 7.1 million companies, 55,000+ sector taxonomies, and human-curated market maps — widely seen as the gold standard for India coverage in private-market data. Daily deal feeds cover funded and unfunded companies across 30+ countries, with financials, cap tables, and acquisition histories. Used by most India-focused VC firms for dealflow discovery in niche categories, competitive benchmarking, and pulling sector reports into thesis work and IC prep.', 'Global startup database with 2,000+ sector taxonomies and curated deal feeds', '["Pull a curated daily deal feed for a specific sub-sector and route it to the CRM","Build a market map of emerging players in a niche taxonomy ahead of a thesis sprint"]', '["7M+ companies across 55,000+ sector taxonomies","Human-curated market maps and daily deal feeds","Coverage of funded and unfunded companies across 30+ countries"]', 'https://tracxn.com', 'https://www.google.com/s2/favicons?domain=tracxn.com&sz=128', 'PAID', 0, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-24', 'twitter', 'Twitter', 'The default real-time public feed, where technical founders ship updates, LPs debate markets, and category conversations unfold in the open. Lists, search, Spaces, and quote posts turn it into a live radar for builder momentum, reputation, and narrative. Used by VCs to spot technical founders building in public, track portfolio signal, and warm up relationships with reply threads long before a first meeting.', 'Real-time public conversation where founders build in public and VCs watch', '["Curate lists of builders in a target sector and watch for repo launches or stealth hints","Engage a founder through thoughtful replies to warm up a cold outreach later in the week"]', '["Real-time public feed where founders, LPs, and operators post in the open","Lists, advanced search, Spaces, and quote posts for live category radar","Reply threads and DMs for warm-up before cold outreach"]', 'https://x.com', 'https://www.google.com/s2/favicons?domain=x.com&sz=128', 'FREE', 0, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-25', 'venture-intelligence', 'Venture Intelligence', 'A veteran India private-markets database with 25,000+ PE/VC transactions and 15,000+ M&A deals going back to 1999, paired with financials on 800,000+ companies. League tables rank funds, bankers, and law firms by activity; APIs expose funding and financial feeds. Used by India-focused VCs for historical comp analysis, competitive benchmarking, and building league-table visibility ahead of LP meetings.', 'India-focused PE, VC, and M&A intelligence with deal data going back to 1999', '["Pull a decade of Indian PE/VC comparable deals to anchor valuation in an IC memo","Track league-table rankings and deal volumes to benchmark the fund against India peers"]', '["25,000+ Indian PE/VC transactions and 15,000+ M&A deals since 1999","League tables ranking funds, bankers, and law firms by activity","API access to funding and financial feeds for in-house workflows"]', 'https://ventureintelligence.info', 'https://www.ventureintelligence.info/static/images/icon.png', 'PAID', 0, NULL, 'cat-2', NULL, NULL, 1777215011764, 1777215011764), ('t-26', '1lattice', '1Lattice', 'An Indian market intelligence platform combining survey panels, expert networks, and sector research into a single workflow. Teams run brand tracking, concept testing, competitive scans, and retail audits, then layer on expert calls when qualitative depth is needed. Investors lean on 1Lattice for primary market sizing, sector deep-dives, and diligence checks on consumer and fintech theses.', 'AI market intelligence platform with B2C/B2B panels and expert networks', '["Run primary consumer surveys to validate market size and pricing assumptions on a prospective consumer investment","Commission expert calls and retail audits during diligence to pressure-test founder claims with ground-truth data"]', '["B2C and B2B survey panels for primary market sizing","Expert calls plus retail audits for ground-truth diligence","Sector deep-dives across consumer, fintech, and B2B"]', 'https://1lattice.com', 'https://www.google.com/s2/favicons?domain=1lattice.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-27', 'ahrefs', 'Ahrefs', 'The reference SEO platform, built on one of the largest web crawlers outside the search engines themselves. Site Explorer, Keywords Explorer, and Content Explorer expose organic traffic, backlink profiles, and keyword rankings for any domain. Investors use it to validate founder-reported growth, map organic competitors in a category, and spot sectors where search demand is quietly compounding.', 'SEO and competitive intelligence toolkit for domain traffic and keyword analysis', '["Verify a startup''s organic traffic trajectory against claimed growth before writing a check","Map search demand and competitive density across a thesis to find under-covered categories"]', '["Site Explorer, Keywords Explorer, and Content Explorer on any domain","One of the largest web crawlers outside the search engines","Backlink profiles, keyword rankings, and organic traffic estimates"]', 'https://ahrefs.com', 'https://assets-3b70.kxcdn.com/images/mediakit/logo_blue@2x.png?v=2', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, short_desc = excluded.short_desc, use_cases = excluded.use_cases, key_features = excluded.key_features, website_url = excluded.website_url, logo_url = excluded.logo_url, pricing_model = excluded.pricing_model, is_featured = excluded.is_featured, featured_order = excluded.featured_order, category_id = excluded.category_id, extra_category_slugs = excluded.extra_category_slugs, archived_at = excluded.archived_at, updated_at = excluded.updated_at;
INSERT INTO tools (id, slug, name, description, short_desc, use_cases, key_features, website_url, logo_url, pricing_model, is_featured, featured_order, category_id, extra_category_slugs, archived_at, created_at, updated_at) VALUES ('t-28', 'alphasense', 'AlphaSense', 'A market intelligence engine that indexes SEC filings, broker research, earnings transcripts, news, and the Tegus library of expert interviews. Generative search and deep research agents surface cited answers across millions of documents, with private workspaces for internal notes and memos. Funds use it to scope new sectors, track portfolio comparables, and pull expert perspectives into diligence without chasing PDFs.', 'AI search across filings, broker research, and expert call transcripts', '["Scan expert transcripts and filings to map competitive dynamics in a new sector before a first meeting","Pull cited quotes from earnings calls and analyst research to stress-test a portfolio company''s thesis"]', '["AI search across 500M+ filings, broker research, and news","Tegus library of expert call transcripts integrated","Deep Research agents with sentence-level citations"]', 'https://alpha-sense.com', 'https://www.google.com/s2/favicons?domain=alpha-sense.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-30', 'clearbit', 'Clearbit', 'A B2B data layer, now part of HubSpot, that enriches emails, domains, and IP addresses into standardised company and contact records. Firmographics, role seniority, industry codes, and corporate hierarchies flow directly into CRMs and forms, with reveal tools exposing which companies visit a website. VC teams wire it into their CRM to enrich inbound dealflow and spot warm intros hiding in team profiles.', 'B2B data enrichment for company, contact, and website visitor intelligence', '["Auto-enrich inbound founder emails with firmographic and team data before the first diligence call","Reveal which portfolio targets are visiting the fund website to prioritise outbound follow-up"]', '["Enriches emails, domains, and IPs into firmographic and contact records","Pushes data into CRMs, forms, and HubSpot workflows","Reveal tool exposing which companies visit a website"]', 'https://clearbit.com', 'https://www.google.com/s2/favicons?domain=clearbit.com&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-31', 'data-ai', 'Data AI', 'Formerly App Annie and now part of Sensor Tower, data.ai tracks download volumes, revenue estimates, active users, retention, and ad spend across mobile apps and games worldwide. Benchmarks span genres, geographies, and publishers, with creative libraries covering the major ad networks. Consumer and gaming investors use it to size categories, benchmark portfolio apps against rivals, and spot breakout titles before they surface in league tables.', 'Mobile market intelligence for app downloads, revenue, and engagement', '["Benchmark a prospective mobile investment''s downloads and revenue against category leaders during diligence","Track portfolio app retention and ad spend share of voice against direct competitors each quarter"]', '["Download, revenue, and engagement estimates for mobile apps and games","Benchmarks across genres, geographies, and publishers","Creative libraries covering the major mobile ad networks"]', 'https://data.ai', 'https://www.google.com/s2/favicons?domain=data.ai&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-32', 'g2', 'G2', 'The default peer review site for B2B software, covering over two hundred thousand products with validated user reviews, category grids, and buyer intent data. Quadrants and momentum scores surface which vendors are gaining traction in a category and where incumbents are slipping. VC teams scan G2 to triangulate product-market fit signals, benchmark SaaS competitors, and read the review voice of customers before writing a term sheet.', 'Peer review marketplace and buyer intent signals for B2B software', '["Compare a target SaaS company against category peers on review velocity, ratings, and satisfaction scores","Read unfiltered customer reviews to surface product gaps and churn risks before a SaaS investment"]', '["200,000+ B2B software products with verified user reviews","Category grids, momentum scores, and buyer-intent signals","Public quadrants comparing vendors on satisfaction and market presence"]', 'https://g2.com', 'https://www.google.com/s2/favicons?domain=g2.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-33', 'glg', 'GLG', 'The largest expert network in the world, with over a million vetted specialists spanning former executives, physicians, engineers, and government officials. Clients book one-on-one consultations, surveys, and advisory engagements, with compliance controls that keep calls inside public-information boundaries. Funds rely on GLG during diligence to talk directly with former operators, channel partners, and customers of a target company before final investment committee.', 'Expert network connecting investors with specialists for diligence calls', '["Book expert calls with former operators and customers to validate a target company''s competitive position","Commission targeted surveys of industry practitioners to test a sector thesis before leading a round"]', '["1M+ vetted experts across operators, executives, and specialists","One-on-one consultations, surveys, and advisory engagements","Compliance controls keeping calls inside public-information boundaries"]', 'https://glginsights.com', 'https://www.google.com/s2/favicons?domain=glginsights.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-34', 'gartner', 'Gartner', 'The dominant research and advisory firm for enterprise technology, with Magic Quadrants, Hype Cycles, and category deep dives on every major software market. Paid subscriptions include analyst inquiry calls, forecast data, and benchmarking libraries. VC firms lean on Gartner reports during diligence to size categories, validate competitive positioning, and pressure-test a founder''s view of where a market is actually heading.', 'Technology research, Magic Quadrants, and analyst advisory for enterprise buyers', '["Size TAM and validate category framing before writing a check with Magic Quadrant context","Book analyst inquiry calls to pressure-test a founder''s roadmap against enterprise buying signals"]', '["Magic Quadrants and Hype Cycles across enterprise software categories","Analyst inquiry calls included with paid subscriptions","Forecast data and benchmarking libraries for category sizing"]', 'https://gartner.com', 'https://www.google.com/s2/favicons?domain=gartner.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-35', 'kavi-research', 'Kavi Research', 'An expert network built for investors researching Indian businesses, with a library of recorded investor-led interviews plus direct expert booking without the usual markups. Experts are operators and domain specialists across consumer, fintech, and B2B sectors. Used by funds to accelerate diligence on Indian companies, stress-test theses, and gather primary signal without running a full consulting engagement or paying GLG-tier rates.', 'Investor-led expert interviews and on-demand expert calls focused on India', '["Pull recorded interviews on a target sector to shortcut the first pass of diligence research","Book direct calls with operators to validate a founder''s channel claims or unit economics"]', '["Library of investor-led recorded expert interviews focused on India","Direct expert booking without GLG-tier markups","Operators and domain specialists across consumer, fintech, and B2B"]', 'https://joinkavi.com', 'https://www.google.com/s2/favicons?domain=joinkavi.com&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-36', 'owler', 'Owler', 'A company intelligence platform built on crowdsourced and editorial data, covering revenue estimates, funding, headcount, news, and competitive sets for millions of private and public companies. Daily alerts and competitor graphs run inside the browser or Salesforce. Used by VC associates to build watchlists on private companies, track portfolio competitor moves, and catch funding or exec-change news before it filters into Crunchbase.', 'Company intelligence with crowd-sourced data and competitor news alerts', '["Set daily alerts on portfolio companies and their competitors to catch funding and exec moves early","Build quick competitor maps during diligence using Owler''s crowdsourced revenue and headcount estimates"]', '["Revenue, headcount, and funding estimates from crowdsourced data","Daily alerts and competitor graphs in browser or Salesforce","Watchlist and competitor map workflows for portfolio monitoring"]', 'https://owler.com', 'https://www.google.com/s2/favicons?domain=owler.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-37', 'redseer', 'RedSeer', 'A strategy consulting and research firm with deep coverage of Indian and MEA consumer, fintech, and B2B markets. Redsights publications and custom reports map category structure, competitive share, and unit economics across sectors from quick commerce to neobanking. Widely used by VC firms investing in India to size markets during diligence, benchmark portfolio companies against category leaders, and commission bespoke theses on emerging verticals.', 'India-focused strategy research on consumer, fintech, and B2B markets', '["Commission custom market maps and sizing studies to anchor investment theses in Indian consumer or fintech","Benchmark a portfolio company''s GMV and take rate against Redseer category data before a follow-on"]', '["Redsights publications and custom reports on India and MEA markets","Coverage across consumer, fintech, and B2B verticals","Category structure, share, and unit-economics benchmarks"]', 'https://redseer.com', 'https://www.google.com/s2/favicons?domain=redseer.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-38', 'semrush', 'SEMRush', 'A digital marketing platform covering keyword research, backlink analysis, site audits, and traffic and market intelligence across competitor domains. The newer AI Visibility module tracks how brands appear inside LLM answers. VC firms use Semrush during diligence to read a startup''s organic traffic trajectory, compare digital share of voice against category incumbents, and check whether paid growth is covering for weak SEO fundamentals.', 'SEO, traffic analytics, and competitive digital marketing intelligence', '["Pull organic traffic and keyword trend charts during diligence to sanity-check a startup''s growth claims","Compare a target''s backlink profile and domain authority against direct competitors in the category"]', '["Keyword research, backlink analysis, and site audits","Competitor traffic and market-share analytics","AI Visibility module tracking brand mentions in LLM answers"]', 'https://semrush.com', 'https://www.google.com/s2/favicons?domain=semrush.com&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-39', 'similarweb', 'Similarweb', 'A digital intelligence platform estimating website and mobile app traffic, engagement, acquisition mix, and audience overlap across millions of properties. Retail modules add marketplace and Amazon analytics. VC firms rely on Similarweb to triangulate user growth on private companies without portal access, map category share between a target and its rivals, and watch traffic trends in portfolio companies quarter over quarter.', 'Web and app traffic intelligence with competitive benchmarking data', '["Triangulate traffic and engagement on private targets when data-room access is limited during early diligence","Track monthly visit share across a category to spot which portfolio bet is pulling ahead of competitors"]', '["Traffic, engagement, and audience overlap on 100M+ websites and 4M+ apps","Acquisition-mix breakdowns and category share-of-voice","Retail and Amazon marketplace analytics modules"]', 'https://similarweb.com', 'https://www.google.com/s2/favicons?domain=similarweb.com&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-40', 'statista', 'Statista', 'A subscription statistics portal aggregating market data, forecasts, and consumer survey results across 170 industries and 150+ countries. Analyst-ready charts and export-friendly datasets cover everything from EV adoption to SaaS spend. Used by investors to anchor market-size slides in memos with citable third-party sources, pull category forecasts for thesis work, and sanity-check TAM numbers a founder has put in a deck.', 'Global statistics portal with market sizing, forecasts, and consumer data', '["Pull citable market-size and forecast charts for memo appendices without commissioning custom research","Sanity-check TAM and CAGR numbers in a pitch deck against Statista''s published consumer and industry data"]', '["Market data and forecasts across 170 industries and 150+ countries","Citable analyst-ready charts and export-friendly datasets","Consumer survey results spanning thousands of categories"]', 'https://statista.com', 'https://www.google.com/s2/favicons?domain=statista.com&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777215011764, 1777215011764), ('t-41', 'arc-news', 'Arc', 'A Bengaluru-based publication from ex-Economic Times and Reuters journalists, decoding the strategies, leadership, and shareholding behind India''s fastest-growing private companies. Formats split between longer In-Depth reads and short Bulletins that cover earnings, org shifts, and cap-table moves. VCs use it to track the private-company narratives that shape portfolio benchmarks and competitive diligence.', 'Data-led reportage on India''s high-growth private companies', '["Read Bulletins to catch cap-table and leadership changes at private Indian companies weekly","Use In-Depth pieces to pressure-test competitive theses before an investment committee or partner meeting"]', '["In-Depth long reads plus short Bulletins on cap-table and leadership moves","Founded by ex-Economic Times and Reuters journalists"]', 'https://thearcweb.com', 'https://www.google.com/s2/favicons?domain=thearcweb.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-42', 'economic-times', 'Economic Times', 'India''s flagship business daily, with live Sensex and Nifty coverage, IPO and earnings tracking, policy reporting, and a dedicated startup desk. The newsroom pairs wire-speed breaking news with opinion columns and sector explainers across banking, energy, telecom, and consumer. VC readers lean on it for macro context, public-market comparables, and early signals on regulation affecting portfolio companies.', 'India''s largest business daily covering markets, companies, policy', '["Skim morning headlines for regulatory and macro developments that affect Indian portfolio companies","Pull public-market comparables and IPO updates when sizing late-stage opportunities for the team"]', '["Live Sensex and Nifty coverage with IPO and earnings tracking","Dedicated startup desk paired with macro and opinion columns"]', 'https://economictimes.indiatimes.com', 'https://www.google.com/s2/favicons?domain=economictimes.indiatimes.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-43', 'entrepreneur-india', 'Entrepreneur India', 'The India edition of Entrepreneur mixes short business-news updates on funding rounds and leadership moves with founder interviews and operator-oriented how-to pieces on marketing, hiring, and fundraising. Coverage skims across D2C, fintech, and emerging tech, with a practical tone pitched at founders rather than institutional investors. Useful for a quick take on what operators are reading in-market.', 'Practical founder stories and India business news with a how-to voice', '["Scan founder features to understand how category leaders are framing their own story","Share operator how-to pieces with portfolio founders working on sales or hiring"]', '["Founder interviews across D2C, fintech, and emerging tech","Operator how-to pieces on marketing, hiring, and fundraising"]', 'https://entrepreneur.com', 'https://www.google.com/s2/favicons?domain=entrepreneur.com&sz=128', 'FREE', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-44', 'forbes', 'Forbes', 'A global business and finance brand known for its wealth rankings, the 30 Under 30 cohort, Cloud 100, and Next Billion-Dollar Startups lists. Daily coverage spans venture capital, enterprise AI, money and markets, leadership, and personal finance, with contributor columns layered over staff reporting. Investors use the lists for surfacing emerging names and the newsroom for global macro and tech context.', 'Global business coverage, billionaire rankings, and startup lists', '["Mine Cloud 100 and Next Billion-Dollar Startups for names worth a warm intro","Reference 30 Under 30 cohorts when mapping rising founders across a target category"]', '["30 Under 30, Cloud 100, and Next Billion-Dollar Startups lists","Wealth rankings layered with contributor and staff reporting"]', 'https://forbes.com', 'https://www.google.com/s2/favicons?domain=forbes.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-45', 'inc42', 'Inc42', 'India''s most-read startup publication, tracking funding rounds, founder moves, and sector shifts across fintech, edtech, healthtech, ecommerce, and EVs. Franchises like What The Financials and 30 Startups To Watch sit alongside running coverage of policy and the unicorn and soonicorn pipeline. Investors use it for a weekday pulse on Indian dealflow and quick context on any named company.', 'India startup media with funding rounds, sector deep dives, policy', '["Read the weekly funding roundup to stay current on Indian early-stage rounds","Pull What The Financials pieces when sizing unit economics on a target company"]', '["Franchises like What The Financials and 30 Startups To Watch","Sector shifts in fintech, edtech, healthtech, ecommerce, and EVs"]', 'https://inc42.com', 'https://www.google.com/s2/favicons?domain=inc42.com&sz=128', 'FREE', 1, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-46', 'the-ken', 'Ken', 'A subscription newsroom publishing one carefully reported story a day across Indian business, startups, technology, and healthcare. Franchise newsletters like The Nutgraf, Daybreak, Trade Tricks, and Two by Two unpack narratives behind the headlines with a calm, analytical voice and few-but-rich editorial cadence. Investors read it for the context and second-order takes the wire services miss.', 'Subscription longform on Indian business, startups, and healthcare', '["Read the daily long story to understand the why behind a competitor''s strategic move","Forward Two by Two frameworks to LPs when explaining Indian category dynamics simply"]', '["One carefully reported longform story a day","Newsletters: The Nutgraf, Daybreak, Trade Tricks, and Two by Two"]', 'https://the-ken.com', 'https://www.google.com/s2/favicons?domain=the-ken.com&sz=128', 'PAID', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-47', 'livemint', 'Live Mint', 'Hindustan Times Group''s business paper, partnered with The Wall Street Journal and The Economist for global coverage. Strong on live markets, company results, mutual funds, personal finance, and the startup desk, with Mint Explainers and Long Story features adding depth. VCs use it for public-market signal, LP-grade macro pieces, and companion context alongside the startup trade press.', 'India business daily with markets, companies, startups, personal finance', '["Check Mint Explainers when a macro or regulatory story needs a quick grounded read","Track company results each quarter to update comparables for late-stage portfolio reviews"]', '["Partnered with The Wall Street Journal and The Economist","Mint Explainers and Long Story features for grounded depth"]', 'https://livemint.com', 'https://www.google.com/s2/favicons?domain=livemint.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-48', 'money-control', 'Money Control', 'India''s most-used financial markets portal, built around live quotes, stock screeners, mutual fund data, and a deep IPO section, with layered coverage of companies, startups, and personal finance. Tools like the fundamental and technical scanners sit next to news, and the MC Pro tier adds research. Investors use it for public-market data, IPO pipelines, and real-time price action on listed comparables.', 'India markets portal covering stocks, IPOs, mutual funds, and startups', '["Pull quick fundamentals and price history when building a public comparable set","Track the IPO pipeline to anticipate exit windows for late-stage portfolio companies"]', '["Deep IPO section with company financials and pipelines","MC Pro tier with research and fundamental/technical scanners"]', 'https://moneycontrol.com', 'https://www.google.com/s2/favicons?domain=moneycontrol.com&sz=128', 'FREE', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-49', 'morning-context', 'The Morning Context', 'Founded by former Ken and Mint journalists, this subscription-only newsroom publishes one longread, one opinion column, and one news explainer each weekday across three themes: Internet, Business, and Chaos. Reporting is deliberately narrow and deep, often revealing the power dynamics and regulatory undercurrents behind startup headlines. Investors subscribe for original scoops that rarely appear in the wire press.', 'Subscription daily on Indian internet, business, and policy chaos', '["Read the daily longread to understand internal dynamics at Indian consumer and fintech players","Forward explainers to LPs when a policy shift changes the shape of a sector"]', '["One longread, one opinion column, one explainer each weekday","Founded by ex-Ken and Mint journalists"]', 'https://themorningcontext.com', 'https://www.google.com/s2/favicons?domain=themorningcontext.com&sz=128', 'PAID', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-50', 'techcrunch', 'TechCrunch', 'The default global wire for startup news, funding announcements, and big tech moves, with heavy AI and venture coverage, plus podcasts like Equity and StrictlyVC. Reporting runs the full stack from seed rounds and acquisitions to product launches at Apple, OpenAI, and Meta. VCs use it for daily deal signal, competitor monitoring, and the fastest read on what US founders are raising on.', 'Global tech and startup news with heavy VC funding coverage', '["Scan the morning feed for US funding rounds that shape global category benchmarks","Use Equity and StrictlyVC podcasts to stay current on Silicon Valley deal sentiment"]', '["Heavy AI and venture coverage with daily deal signal","Equity and StrictlyVC podcasts for Silicon Valley sentiment"]', 'https://techcrunch.com', 'https://www.google.com/s2/favicons?domain=techcrunch.com&sz=128', 'FREE', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-51', 'the-generalist', 'The Generalist', 'Mario Gabriele''s subscriber newsletter with over 160,000 readers, built around long-form deep dives on private companies, venture firms, and frontier themes across tech and Web3. Writing is essay-length and thesis-driven rather than newsy, with investor-friendly framing and clean charts. VCs read it for category maps and founder-and-firm profiles that hold up as reference material long after publication.', 'Mario Gabriele''s deep dives on tech companies, VC, and frontier themes', '["Read company deep dives before taking a first meeting with a category-adjacent founder","Share VC firm profiles with LPs to anchor discussion of peer fund strategies"]', '["Mario Gabriele''s subscriber newsletter with 160K+ readers","Long-form deep dives on private companies, VC firms, and frontier tech"]', 'https://generalist.com', 'https://www.google.com/s2/favicons?domain=generalist.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-52', 'vccircle', 'VCCircle', 'The trade publication of record for Indian private equity, venture capital, and M&A, with sections dedicated to fund closes, LP activity, exits, and sector deal flow across healthcare, infrastructure, TMT, and consumer. The LP Corner franchise tracks fund raises and GP interviews rarely covered elsewhere. Funds use the Premium tier for competitive intel on peer firms and sector deal tempo.', 'India PE, VC, and M&A trade press with LP and fund coverage', '["Track LP Corner for peer fund raises and incoming capital in your strategy","Monitor M&A and exit coverage to benchmark return multiples across Indian sectors"]', '["LP Corner franchise tracking fund closes and LP activity","Premium tier for peer-fund competitive intel"]', 'https://vccircle.com', 'https://www.google.com/s2/favicons?domain=vccircle.com&sz=128', 'PAID', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-53', 'yourstory', 'YourStory', 'One of India''s oldest startup media platforms, known for accessible founder profiles, weekly funding roundups, and the Unicorns of India franchise. Coverage spans AI, fintech, agritech, D2C, and women-led businesses, with a narrative-first tone that reaches beyond the insider audience. Investors use it to spot early-stage founders and to read how portfolio companies are framing their own stories to a broader audience.', 'India startup media built around founder stories and weekly roundups', '["Read founder profiles to surface emerging names before institutional coverage catches up","Share weekly funding roundups with junior team members to build sector context"]', '["Founder profiles spanning AI, fintech, agritech, D2C, and women-led","Unicorns of India franchise with narrative-first tone"]', 'https://yourstory.com', 'https://www.google.com/s2/favicons?domain=yourstory.com&sz=128', 'FREE', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, short_desc = excluded.short_desc, use_cases = excluded.use_cases, key_features = excluded.key_features, website_url = excluded.website_url, logo_url = excluded.logo_url, pricing_model = excluded.pricing_model, is_featured = excluded.is_featured, featured_order = excluded.featured_order, category_id = excluded.category_id, extra_category_slugs = excluded.extra_category_slugs, archived_at = excluded.archived_at, updated_at = excluded.updated_at;
INSERT INTO tools (id, slug, name, description, short_desc, use_cases, key_features, website_url, logo_url, pricing_model, is_featured, featured_order, category_id, extra_category_slugs, archived_at, created_at, updated_at) VALUES ('t-54', 'entrackr', 'Entrackr', 'A scoop-driven Indian startup newsroom, known for breaking funding rounds, ESOP buyback moves, and leadership changes ahead of the broader press. The Fintrackr franchise pulls revenue, loss, and GMV data from regulatory filings into readable company snapshots. Investors use it for the earliest word on rounds in motion and for quick pre-meeting financial context on any privately held Indian target.', 'India startup scoops, funding rounds, and company financials', '["Check Fintrackr for filed financials before a first meeting with a private Indian company","Monitor exclusive scoops for rounds in motion to time outbound on competitive deals"]', '["Scoops on funding rounds and ESOP buyback moves","Fintrackr franchise extracting financials from MCA filings"]', 'https://entrackr.com', 'https://www.google.com/s2/favicons?domain=entrackr.com&sz=128', 'FREE', 0, NULL, 'cat-4', NULL, NULL, 1777215011764, 1777215011764), ('t-55', 'chatgpt', 'ChatGPT', 'For VC firms, ChatGPT is the everyday AI surface for memo drafting, market research, diligence, and LP communications. Custom GPTs on firm playbooks turn it into a portable reasoning layer with document analysis, browsing, canvas, voice, image gen, and Deep Research. Atlas, OpenAI''s browser, pipes every page and search the team views into ChatGPT context. The API wires into proprietary tools for screening, founder profiling, and portfolio analysis.', 'The most widely adopted AI product, now a general reasoning layer', '["Memo drafting — synthesise founder decks, market research, and competitive data into structured investment thesis documents","Market research automation — pull market sizes, competitive landscapes, and industry trends for target companies and sectors","Due diligence analysis — process data room documents to extract key insights and surface red flags during evaluation","LP communications — draft quarterly reports, investor updates, and fundraising materials with consistent firm tone"]', '["Custom GPTs trained on firm playbooks and portfolio data","Document analysis, browsing, canvas, voice, image gen, and Deep Research","API access for custom internal tools and screening pipelines"]', 'https://openai.com', 'https://www.google.com/s2/favicons?domain=openai.com&sz=128', 'FREEMIUM', 1, NULL, 'cat-5', NULL, NULL, 1777215011764, 1777215011764), ('t-56', 'claude', 'Claude', 'Anthropic''s AI assistant, favoured for long-context reading, careful writing, and code analysis. VC firms use Claude to draft memos, synthesise data rooms, and turn unstructured documents into structured diligence notes. Skills let teams package firm SOPs — memo formats, diligence checklists, deck triage — into reusable agents that scale repeatable workflows across the fund. Projects, Artifacts, and Claude Code round out the workspace for per-deal context, inline drafts, and terminal-level work.', 'Anthropic''s assistant favoured for long-context reasoning and writing', '["Memo drafting — process founder decks, market research, and competitive data into structured investment thesis documents","Data room synthesis — read virtual data room files, customer references, and market reports to surface risks and opportunities","Portfolio reporting — generate quarterly LP updates from KPIs, market conditions, and portfolio performance metrics","Skills for SOPs — package recurring tasks like memo formatting, deck triage, or diligence checklists into firm-specific reusable agents"]', '["Long-context reading on data rooms, memos, and filings with citations","Skills package firm SOPs into reusable agents for repeatable workflows","Projects, Artifacts, and Claude Code for per-deal context, inline drafts, and terminal work"]', 'https://claude.ai', 'https://www.google.com/s2/favicons?domain=claude.ai&sz=128', 'FREEMIUM', 1, NULL, 'cat-5', NULL, NULL, 1777215011764, 1777215011764), ('t-57', 'gemini', 'Gemini', 'Google''s AI assistant, plugged directly into Gmail, Docs, Sheets, Drive, and Search inside Workspace. VC firms already living in Workspace use Gemini for first-pass diligence research, market sizing, competitive scans, and memo synthesis without leaving the inbox or doc. Deep Research runs autonomous multi-step investigations, and the 1M-token context window suits long data rooms and messy decks.', 'Google''s AI assistant plugged into Workspace, Search, and the browser', '["Due diligence research — generate market analyses and competitive landscape summaries for target investments inside Docs and Sheets","Memo writing — draft and refine investment memos with research findings synthesised straight from Drive and Gmail context","Market sizing — create preliminary TAM, SAM, and SOM estimates for new investment opportunities with cited sources","Competitive intelligence — research competitor positioning, funding history, and strategic moves in target sectors before a thesis lock-in"]', '["Built into Gmail, Docs, Sheets, Drive, and Search inside Google Workspace","Deep Research runs autonomous multi-step investigations","1M-token context window for long documents and messy decks"]', 'https://gemini.google.com', 'https://www.google.com/s2/favicons?domain=gemini.google.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-5', NULL, NULL, 1777215011764, 1777215011764), ('t-58', 'manus', 'Manus', 'An autonomous AI agent that takes a brief and returns finished work, not just a reply. Manus plans a task, opens a browser, writes code, builds slide decks or websites, and hands back a file. Wide Research runs parallel sub-agents across the open web. Used by VC teams to assemble market maps, build competitor teardowns, and draft sector decks without wiring up a research stack.', 'Autonomous AI agent that plans, browses, and delivers finished work', '["Build market maps and competitor teardowns by pointing the agent at a sector brief","Turn raw research notes into a polished slide deck or memo the team can edit"]', '["Autonomous agent that browses, codes, and delivers finished files","Wide Research runs parallel sub-agents across the open web","Outputs market maps, decks, and websites without a research stack"]', 'https://manus.ai', 'https://www.google.com/s2/favicons?domain=manus.ai&sz=128', 'PAID', 0, NULL, 'cat-5', NULL, NULL, 1777215011764, 1777215011764), ('t-60', 'perplexity', 'Perplexity', 'An AI answer engine built for fast factual research with citations on every response. VC firms use Perplexity for sourcing market intelligence, validating investment theses, and prepping partner meetings with grounded sources. Pro opens up additional models, document search, and Spaces for saved per-thesis context. Comet adds an AI browser, and Pages produces shareable research reports.', 'AI answer engine that cites its sources on every response', '["Due diligence research — research target companies, their competitors, and recent developments with cited sources you can paste into a memo","Market analysis — gather real-time market intelligence, industry trends, and TAM data to validate investment theses","Competitive benchmarking — analyse competitive landscapes, identify key players, and map market dynamics for portfolio prospects","Deal preparation — quickly research founders, company backgrounds, and market context before first meetings or pitch reviews"]', '["AI answer engine with citations on every response","Spaces for saved per-thesis research and document search","Comet AI browser and Pages for shareable research reports"]', 'https://perplexity.ai', 'https://www.google.com/s2/favicons?domain=perplexity.ai&sz=128', 'FREEMIUM', 1, NULL, 'cat-5', NULL, NULL, 1777215011764, 1777215011764), ('t-62', 'deepseek', 'DeepSeek', 'A Chinese AI lab shipping strong open-source reasoning and coding models alongside a free chat app and a low-cost API. The V3 and R1 lines are widely benchmarked against frontier closed models, and the weights are downloadable for private deployment. Used by VC analysts as a second AI opinion and for high-volume tasks like deck OCR and document parsing where premium-model token costs add up.', 'Open-source reasoning models with a free chat app and cheap API', '["Run a second-opinion reasoning pass on memos, models, and technical diligence questions","Self-host an open-weight model for sensitive documents that cannot leave the firm"]', '["Open-source V3 and R1 models with downloadable weights","Free chat app and low-cost API for high-volume tasks like deck OCR and document parsing","Self-hostable for sensitive documents that cannot leave the firm"]', 'https://deepseek.com', 'https://www.google.com/s2/favicons?domain=deepseek.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-5', NULL, NULL, 1777215011764, 1777215011764), ('t-63', 'standard-metrics', 'Standard Metrics', 'A portfolio management platform built for VC and PE firms, covering automated data collection from founders, structured metrics storage, an AI analyst for natural-language queries, and benchmarking against 10,000+ venture-backed companies. Used by funds to cut reporting time, standardise KPIs across the book, and produce LP updates and dashboards without rebuilding spreadsheets every quarter.', 'Portfolio monitoring and LP reporting with benchmarks against 10,000+ startups', '["Automate quarterly KPI collection from founders and normalise metrics across the fund''s entire portfolio","Generate LP reports and benchmark a portfolio company''s growth against anonymised peer data by stage"]', '["Automated quarterly KPI collection from founders","Benchmarking against 10,000+ anonymised venture-backed companies","AI analyst answering natural-language questions across the book"]', 'https://standardmetrics.io', 'https://www.google.com/s2/favicons?domain=standardmetrics.io&sz=128', 'PAID', 0, NULL, 'cat-6', NULL, NULL, 1777215011764, 1777215011764), ('t-64', 'vestberry', 'Vestberry', 'An AI-powered portfolio platform that consolidates fund, company, and market data into a single workspace for venture investors. Modules handle automated data collection from founders, institutional-grade LP reports, and analytics that flag underperforming bets against market comps. Used by 500+ funds to retire spreadsheet-based tracking, standardise reporting cadence across the portfolio, and give partners a live view of fund performance between board meetings.', 'VC portfolio monitoring with automated data collection and LP reporting', '["Replace spreadsheet trackers with automated KPI pulls and a shared dashboard across the full portfolio","Build audit-ready LP reports and flag underperforming companies using Vestberry''s benchmark analytics"]', '["Real-time portfolio dashboards with IRR, MOIC, and fair-value calcs","Institutional-grade LP reports with ILPA-aligned templates","Benchmarks portfolio companies against market comps"]', 'https://vestberry.com', 'https://www.google.com/s2/favicons?domain=vestberry.com&sz=128', 'PAID', 0, NULL, 'cat-6', NULL, NULL, 1777215011764, 1777215011764), ('t-71', 'angellist', 'AngelList', 'AngelList India runs the legal, banking, and software rails behind Indian syndicates, SPVs, and rolling funds. Roll-Up Vehicles, pre-funded SPVs, and warehouse structures cover different deal patterns, and the platform handles onboarding, capital calls, distributions, and tax paperwork. Used by Indian angels, scouts, and emerging managers to run deal-by-deal vehicles without assembling lawyers, fund admins, and bankers for every investment.', 'India''s default platform for running syndicates, SPVs, and rolling funds', '["Spin up an SPV or RUV per deal and onboard LPs with KYC, capital calls, and distributions handled","Run a rolling fund or syndicate with investor dashboards, reporting, and tax forms built in"]', '["Roll-Up Vehicles, pre-funded SPVs, and warehouse structures","Built-in legal, banking, and software rails for Indian deals"]', 'https://angellistindia.com', 'https://www.google.com/s2/favicons?domain=angellistindia.com&sz=128', 'PAID', 1, NULL, 'cat-9', NULL, NULL, 1777215011764, 1777215011764), ('t-72', 'incentive-finance', 'Incentive Finance', 'Incentiv positions itself as infrastructure for private markets, building the admin and investor-facing rails that sit under Indian syndicates, SPVs, and private deals. The platform covers vehicle setup, investor onboarding, and ongoing operations so deal leads can run transactions end to end. Used by Indian angels, syndicate leads, and emerging managers who want a modern stack rather than stitching together lawyers, fund admins, and spreadsheets.', 'Infrastructure layer for Indian private market deals and syndicates', '["Structure and launch an SPV or syndicate vehicle for a specific Indian private market deal","Onboard investors, manage capital calls, and keep LP reporting in one dashboard"]', '["Vehicle setup and investor onboarding for SPVs and syndicates","Modern stack alternative to lawyers, fund admins, and spreadsheets"]', 'https://incentiv.finance', 'https://www.google.com/s2/favicons?domain=incentiv.finance&sz=128', 'PAID', 0, NULL, 'cat-9', NULL, NULL, 1777215011764, 1777215011764), ('t-73', 'infinyte-club', 'Infynite Club', 'Infinyte Club is a wealth platform aimed at Indian founders, operators, and angels, registered as a Category-I Angel Fund. Members track net worth across accounts, access curated public-market portfolios, and invest alongside established angels and VCs in seed to pre-IPO rounds. Used by eligible Indian angel investors who want structured access to private deals and a single view of their portfolio across asset classes.', 'Wealth and private-market platform for Indian founders and operators', '["Co-invest alongside established angels and VCs in curated Indian seed and growth rounds","Track net worth, public portfolios, and private holdings across accounts in one dashboard"]', '["Net-worth tracking across public and private holdings","Co-invest access alongside established angels and VCs"]', 'https://infinyte.club', 'https://www.google.com/s2/favicons?domain=infinyte.club&sz=128', 'PAID', 0, NULL, 'cat-9', NULL, NULL, 1777215011764, 1777215011764), ('t-74', 'letsventure', 'LetsVenture', 'LetsVenture, now operating under LVX Ventures, is one of India''s longest-running platforms for angel investing and syndication. It covers deal discovery, syndicate formation, trust-based AIF structures, and fund administration for angels, family offices, and emerging managers. Used by Indian investors to source rounds, run syndicates with pooled LPs, and manage the paperwork and reporting that sit behind each vehicle.', 'Long-running Indian angel and syndication platform for startups and funds', '["Discover Indian startup rounds and form syndicates of angels to back a single deal","Run an AIF or trust-based fund with onboarding, capital calls, and LP reporting handled"]', '["Deal discovery and syndicate formation for Indian rounds","Trust-based AIF structures and fund administration"]', 'https://letsventure.com', 'https://www.google.com/s2/favicons?domain=letsventure.com&sz=128', 'PAID', 0, NULL, 'cat-9', NULL, NULL, 1777215011764, 1777215011764), ('t-75', 'make', 'Make', 'Make is a visual automation platform where workflows are drawn as node-and-line scenarios rather than linear rules. It connects more than 3,000 apps, supports branching, iteration, and error handling, and now ships AI agents that orchestrate steps dynamically. Used by VC ops and platform teams to pipe deal data between CRM, forms, email, and Slack without writing code.', 'Visual automation builder connecting 3,000+ apps with AI agents', '["Route inbound decks from forms and email into CRM with enrichment and Slack alerts","Build agent-driven scenarios that summarise founder updates and post them to the right channel"]', '["3,000+ app integrations on a visual node-based canvas","Branching, iteration, and error handling in scenarios","AI agents that orchestrate workflow steps dynamically"]', 'https://make.com', 'https://www.google.com/s2/favicons?domain=make.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-10', NULL, NULL, 1777215011764, 1777215011764), ('t-76', 'phantombuster', 'Phantom Buster', 'PhantomBuster runs cloud-based automations called Phantoms that scrape, enrich, and act on data from LinkedIn, Sales Navigator, and other sites. It chains prospecting, enrichment, and outreach into repeatable flows, with CRM sync and a Chrome extension for manual steps. Used by VC sourcing and platform teams to build founder and operator lists, map portfolios, and run warm-intro campaigns at scale.', 'LinkedIn-first automation for scraping, enrichment, and outreach', '["Scrape LinkedIn events, company pages, and Sales Nav searches into enriched founder lists","Automate LinkedIn connection requests and message follow-ups for sourcing and portfolio talent pipelines"]', '["Cloud-based Phantoms scrape LinkedIn, Sales Nav, and other sites","Chains prospecting, enrichment, and outreach into repeatable flows","CRM sync with a Chrome extension for manual steps"]', 'https://phantombuster.com', 'https://www.google.com/s2/favicons?domain=phantombuster.com&sz=128', 'PAID', 0, NULL, 'cat-10', NULL, NULL, 1777215011764, 1777215011764), ('t-77', 'zapier', 'Zapier', 'Zapier is the default no-code automation layer connecting more than 9,000 apps through triggers and actions called Zaps. Tables holds light databases, Interfaces builds simple front-ends, Canvas diagrams flows, and Agents run AI steps across the same integrations. Used by VC platform and operations teams to wire deal intake forms, CRM, email, and Slack into a single pipeline without an engineer in the loop.', 'The default no-code automation layer across 9,000+ apps', '["Push new CRM deals into Slack, Notion, and data rooms without writing integration code","Automate newsletter intake, event RSVPs, and inbound triage straight from forms and email"]', '["9,000+ app integrations through trigger-action Zaps","Tables, Interfaces, and Canvas for light databases and front-ends","AI agents running steps across the same integrations"]', 'https://zapier.com', 'https://www.google.com/s2/favicons?domain=zapier.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-10', NULL, NULL, 1777215011764, 1777215011764), ('t-79', 'discord', 'Discord', 'Discord is a real-time chat platform built around persistent servers split into voice, video, and text channels. Members drop into rooms, jump between live huddles, and keep searchable threads alongside bots and custom integrations. Originally built for gaming communities, it is now widely used by VC firms and founders to run scout networks, investor-only communities, and public founder hangouts that would feel too heavy for Slack.', 'Server-based chat platform with voice, video, and topic channels', '["Host a scout community where drive-by voice rooms and topic channels keep deal chatter flowing","Run a portfolio or LP community with gated channels, live AMAs, and searchable message history"]', '["Persistent servers split into voice, video, and text channels","Bots and custom integrations on top of every server"]', 'https://discord.com', 'https://www.google.com/s2/favicons?domain=discord.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-11', NULL, NULL, 1777215011764, 1777215011764), ('t-80', 'slack', 'Slack', 'Slack is the default platform for internal team communication, with channels, threads, and shared rooms that replace endless reply-all email. Huddles add lightweight audio and video, canvas captures decisions in context, and the app directory pipes alerts from CRMs, databases, and project tools into the place teams already look. Widely used by VC firms for partner discussion, shared channels with portfolio companies, and the searchable team memory the inbox never provides.', 'Channel-based team chat with huddles, canvas, and deep app integrations', '["Run shared Slack Connect channels with portfolio companies for fast investor support and introductions","Pipe CRM, data room, and Affinity alerts into partner channels so dealflow stays visible"]', '["Channels, threads, and Slack Connect for cross-firm chat","App directory piping CRM, data, and project alerts into one place"]', 'https://slack.com', 'https://www.google.com/s2/favicons?domain=slack.com&sz=128', 'FREEMIUM', 1, NULL, 'cat-11', NULL, NULL, 1777215011764, 1777215011764), ('t-81', 'telegram', 'Telegram', 'Telegram is a cloud-first messenger built around speed, unlimited media, and groups that scale to 200,000 members. Broadcast channels push one-to-many updates, bots automate workflows through an open API, and chats sync instantly across mobile, desktop, and web. Widely used by VC firms in emerging markets to coordinate with founders, run private deal rooms, and follow crypto and growth-stage communities that live there by default.', 'Fast cloud messenger with large groups, broadcast channels, and open bot APIs', '["Maintain direct lines to portfolio founders in markets where Telegram is the default app","Monitor crypto and emerging-market deal channels where announcements break before Twitter picks them up"]', '["Cloud-first messenger with groups up to 200,000 members","Broadcast channels and bots through an open API"]', 'https://telegram.org', 'https://www.google.com/s2/favicons?domain=telegram.org&sz=128', 'FREE', 0, NULL, 'cat-11', NULL, NULL, 1777215011764, 1777215011764), ('t-82', 'whatsapp', 'WhatsApp', 'WhatsApp is the most widely used messaging app in the world, built around encrypted one-to-one chats, group threads, and voice and video calls. Status updates, broadcast lists, and the Business app add light CRM on top of conversation. Widely used by VC firms outside the US to stay in founder chats, route warm intros, and handle fast diligence back-and-forth where email would feel slow and Slack would feel too formal.', 'Encrypted messenger for one-to-one chats, groups, and business threads', '["Keep direct founder threads active for quick check-ins and intro requests between formal updates","Coordinate warm intros and diligence questions across India, SEA, LatAm, and Africa dealflow"]', '["End-to-end encrypted one-to-one chats and group threads","WhatsApp Business app adds light CRM on top of conversations"]', 'https://whatsapp.com', 'https://www.google.com/s2/favicons?domain=whatsapp.com&sz=128', 'FREE', 1, NULL, 'cat-11', NULL, NULL, 1777215011764, 1777215011764), ('t-83', 'notion-mail', 'Notion Mail', 'Notion Mail is an AI email client built into the Notion ecosystem and layered over Gmail. It auto-labels messages and splits the inbox into custom views by sender, domain, label, or calendar, and the Notion-style editor makes composing feel like a doc. Still maturing as a standalone email client; best fit for VC firms already living in Notion who want a lighter-touch triage layer without adopting a separate power-user client.', 'AI email client that sorts Gmail into custom views with Notion-native editing', '["Triage founder intros, LP threads, and portfolio updates into separate views without filter-rule bookkeeping","Compose investment updates and follow-ups with snippets and formatting that match existing Notion docs"]', '["AI auto-labels and custom inbox views over Gmail","Snippets and Notion-style editor for fast composing"]', 'https://mail.notion.com', 'https://www.google.com/s2/favicons?domain=mail.notion.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-12', NULL, NULL, 1777215011764, 1777215011764), ('t-84', 'shortwave', 'Shortwave', 'Shortwave is an AI-native email app layered over Gmail. The assistant writes, schedules, and searches from a single prompt, bundles collapse newsletters and promotions, and split inbox separates important threads from everything else. Natural-language filters automate labels and archives in plain English. Used by VC firms that want Superhuman-style speed with a stronger AI backbone for memo drafting, research threads, and calendar work.', 'AI-native Gmail client with bundles, split inbox, and natural-language agents', '["Summarise long founder update threads and draft replies in the partner''s voice with the AI agent","Auto-bundle LP newsletters, data-room alerts, and portfolio reports into dedicated split-inbox tabs"]', '["Single AI prompt for write, schedule, and search across Gmail","Bundles for newsletters and split inbox for important threads"]', 'https://shortwave.com', 'https://www.google.com/s2/favicons?domain=shortwave.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-12', NULL, NULL, 1777215011764, 1777215011764), ('t-85', 'simplehuman-mail', 'Simplehuman', 'CMDK (formerly Simplehuman) is a Chrome extension that sits on top of Gmail and adds the keyboard-first muscle of pricier clients. A command palette runs everything, single-key actions archive and delete, natural-language snoozing sets reminders, and read receipts track when messages are reopened. Used by VC firms that want Superhuman-style triage speed inside native Gmail without moving their inbox or paying the premium tier.', 'Keyboard-first Gmail extension with a command bar, snooze, and read receipts', '["Clear a 200-message inbox with single-key triage and command-bar actions instead of clicking menus","Snooze founder follow-ups and LP threads in plain English and catch reopened replies with read receipts"]', '["Command palette and single-key actions inside native Gmail","Read receipts and keyboard-first triage as a Chrome extension"]', 'https://simplehuman.email', 'https://www.google.com/s2/favicons?domain=simplehuman.email&sz=128', 'PAID', 0, NULL, 'cat-12', NULL, NULL, 1777215011764, 1777215011764), ('t-86', 'superhuman', 'Superhuman', 'Used by VC partners who treat email speed as a competitive edge, Superhuman is the premium email client for inbox-first work. Sub-100ms keystrokes and a command palette run every action without a mouse. Split Inbox separates deal flow, portfolio, LP updates, and peer-investor threads so nothing falls through, while AI triage, AI Write, follow-up reminders, send later, and read status remove the usual friction.', 'Keyboard-first email client with AI triage, split inbox, and send-later', '["Split inbox — separate deal flow, portfolio, LP updates, compliance, and peer-investor threads into dedicated inboxes so nothing falls through","Inbox triage — clear founder-heavy threads at twice normal speed with single-key shortcuts and instant load","AI replies — draft warm intros, diligence questions, and follow-ups with AI Write in the partner''s voice","Follow-up workflows — send later, follow-up reminders, and read receipts that surface every dropped thread before deals stall"]', '["Split Inbox separates deal flow, portfolio, LP updates, and peer-investor threads","Sub-100ms keystrokes and a full command palette for every action","AI triage, AI Write in your voice, send later, and read receipts built in"]', 'https://superhuman.com', 'https://www.google.com/s2/favicons?domain=superhuman.com&sz=128', 'PAID', 1, NULL, 'cat-12', NULL, NULL, 1777215011764, 1777215011764), ('t-87', 'cal-com', 'Cal.com', 'Cal.com is an open-source scheduling platform that handles bookings, routing, and workflow automation for individuals and teams. It plugs into Google, Outlook, and Apple calendars, runs round-robin and collective events, and exposes an API plus Docker image for firms that want to self-host. Used by VC firms as a Calendly alternative where brand control, privacy, and custom forms for founder intake matter more than the default option.', 'Open-source scheduling platform with routing, workflows, and a self-host option', '["Route inbound founder pitches to the right partner by stage, sector, or geography with a single public link","Self-host scheduling for LP and portfolio meetings where data residency and branding need to stay in-house"]', '["Open-source scheduling with self-host option via Docker and API","Round-robin and collective events with workflow automation"]', 'https://cal.com', 'https://www.google.com/s2/favicons?domain=cal.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-13', NULL, NULL, 1777215011764, 1777215011764) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, short_desc = excluded.short_desc, use_cases = excluded.use_cases, key_features = excluded.key_features, website_url = excluded.website_url, logo_url = excluded.logo_url, pricing_model = excluded.pricing_model, is_featured = excluded.is_featured, featured_order = excluded.featured_order, category_id = excluded.category_id, extra_category_slugs = excluded.extra_category_slugs, archived_at = excluded.archived_at, updated_at = excluded.updated_at;
INSERT INTO tools (id, slug, name, description, short_desc, use_cases, key_features, website_url, logo_url, pricing_model, is_featured, featured_order, category_id, extra_category_slugs, archived_at, created_at, updated_at) VALUES ('t-88', 'calendly', 'Calendly', 'Calendly is the default scheduling platform for sharing availability without the back-and-forth. It supports one-on-one, collective, round-robin, and group events, routes inbound forms to the right owner, and syncs with Google, Outlook, Zoom, Salesforce, and HubSpot. Meeting reminders, workflows, and a built-in notetaker cover the edges. Widely used by VC firms to book founder intros, run diligence calls, and coordinate LP meetings without owning the scheduling logic.', 'Scheduling platform with routing, team events, and 100+ tool integrations', '["Share a partner booking link for founder intros that respects availability across Gmail and Outlook","Route inbound pitch forms to the right investor by sector or stage with round-robin fallbacks"]', '["One-on-one, collective, round-robin, and group event types","Routing forms direct inbound bookings to the right owner"]', 'https://calendly.com', 'https://www.google.com/s2/favicons?domain=calendly.com&sz=128', 'FREEMIUM', 1, NULL, 'cat-13', NULL, NULL, 1777215011764, 1777215011764), ('t-89', 'notion-calendar', 'Notion Calendar', 'Notion Calendar pulls Google, Apple, and Zoom accounts into one polished view and layers Notion database deadlines on top. Time-zone overlays, shared availability links, scheduling snippets for one-off and recurring meetings, and a menu bar showing the next meeting make scheduling effortless. A favourite among VC firms already living in Notion who want pipeline deadlines, IC dates, and portfolio reviews alongside the live calendar.', 'Calendar app that unifies Google, Apple, and Zoom with Notion database events', '["See Notion pipeline deadlines and portfolio review dates alongside live Google or Outlook meetings","Share availability links and booking snippets for one-off and recurring founder meetings without leaving the app","Run cross-timezone scheduling with overlap views that surface the right slot in seconds"]', '["Unified view across Google, Apple, and Zoom accounts","Layers Notion database deadlines onto the calendar","Time-zone overlays, scheduling snippets, and shared availability links"]', 'https://calendar.notion.so', 'https://www.google.com/s2/favicons?domain=calendar.notion.so&sz=128', 'FREEMIUM', 0, NULL, 'cat-13', NULL, NULL, 1777215011764, 1777215011764), ('t-90', 'vimcal', 'Vimcal', 'Vimcal is a keyboard-first calendar built for people who run dense schedules. Sub-100ms shortcuts, natural-language event creation, and time-zone overlap views cut the friction out of coordinating across regions. Focus mode, attendee profiles, and a dedicated EA surface round it out. Widely used by VC firms and their assistants to triage hundreds of weekly requests across founder calls, board meetings, and LP dinners without the calendar becoming the bottleneck.', 'Keyboard-first calendar built for heavy schedules, time zones, and EA workflows', '["Book cross-timezone founder and LP calls instantly by typing in natural language instead of dragging slots","Hand EAs a dedicated workflow to manage partner schedules, travel blocks, and board meeting chains"]', '["Sub-100ms keyboard shortcuts for dense schedules","Dedicated EA surface for assistant-managed calendars"]', 'https://vimcal.com', 'https://www.google.com/s2/favicons?domain=vimcal.com&sz=128', 'PAID', 0, NULL, 'cat-13', NULL, NULL, 1777215011764, 1777215011764), ('t-91', 'circleback', 'Circleback', 'Circleback is an AI meeting assistant for Zoom, Google Meet, Teams, Slack huddles, and in-person conversations. It produces accurate transcripts in 100+ languages, structured notes, and assigned action items, then runs workflows into Gmail, Slack, HubSpot, Salesforce, Notion, and Zapier. Used by VC firms to keep partner meetings and founder calls searchable without manual writeups.', 'AI meeting notetaker that writes structured notes, action items, and automations', '["Auto-capture founder call notes and push action items into HubSpot or Notion","Search every past meeting for what a portfolio CEO said about hiring or runway"]', '["Captures Zoom, Meet, Teams, Slack huddles, and in-person calls","Transcripts in 100+ languages with structured notes","Workflow automations into Gmail, Slack, HubSpot, Salesforce, Notion"]', 'https://circleback.ai', 'https://www.google.com/s2/favicons?domain=circleback.ai&sz=128', 'PAID', 0, NULL, 'cat-14', NULL, NULL, 1777215011764, 1777215011764), ('t-92', 'fathom', 'Fathom', 'Fathom records Zoom, Google Meet, and Microsoft Teams calls, then delivers AI summaries, action items, and searchable transcripts within minutes of hanging up. A new desktop app captures without a visible bot, and meeting data pipes into Slack, Salesforce, HubSpot, Asana, and Notion. Used by VC firms to keep founder calls present rather than pecking notes on screen.', 'AI notetaker that summarises calls and syncs to Slack, HubSpot, and Salesforce', '["Stay present on founder pitches and get a clean memo-ready summary after the call","Sync call notes and action items into HubSpot or Affinity without copy-paste"]', '["Records Zoom, Meet, and Teams with AI summaries minutes after the call","Desktop app captures without a visible bot","Pipes meeting data into Slack, Salesforce, HubSpot, Asana, and Notion"]', 'https://fathom.ai', 'https://www.google.com/s2/favicons?domain=fathom.ai&sz=128', 'FREEMIUM', 1, NULL, 'cat-14', NULL, NULL, 1777215011764, 1777215011764), ('t-93', 'fireflies', 'Fireflies', 'Fireflies.ai transcribes, summarises, and analyses meetings across Zoom, Google Meet, Teams, and uploaded recordings, with speaker recognition in 100+ languages. AskFred answers questions across the meeting library, and Fireflies auto-populates CRMs and task tools through 200+ integrations. Used by VC firms to build a searchable memory of every founder call and partner discussion.', 'Meeting transcription and AI assistant with searchable archive across 200+ apps', '["Transcribe a pitch call and ask AskFred what the founder said about metrics","Auto-log meeting summaries, action items, and next steps into Salesforce, HubSpot, or Affinity"]', '["Transcribes Zoom, Meet, Teams in 100+ languages with speaker recognition","AskFred answers questions across the entire meeting library","200+ integrations auto-populate CRMs and task tools"]', 'https://fireflies.ai', 'https://www.google.com/s2/favicons?domain=fireflies.ai&sz=128', 'FREEMIUM', 0, NULL, 'cat-14', NULL, NULL, 1777215011764, 1777215011764), ('t-94', 'granola', 'Granola', 'Granola is the AI notepad VC investors trust for back-to-back founder calls — it transcribes computer audio locally without sending a bot into Zoom, Meet, Teams, or Webex. You type sparse notes during the call, and Granola enhances them into structured writeups using the full transcript. Templates for first-meeting notes, founder deep dives, and portfolio check-ins, plus chat-with-transcript and one-click export to Slack, Notion, and CRMs.', 'Meeting notepad that listens locally and enhances the notes you type', '["Founder pitches — type sparse notes during the call and get a clean structured writeup with key metrics, themes, and action items afterwards","Portfolio check-ins — run custom templates per portfolio company to capture KPIs, asks, and follow-ups consistently","Diligence calls — chat with the full transcript to pull quotes, claims, and red flags into a memo"]', '["Local audio capture without sending a bot into Zoom, Meet, Teams, or Webex","Enhances sparse typed notes into structured writeups using the full transcript","Templates, chat-with-transcript, and one-click export to Slack, Notion, and CRMs"]', 'https://granola.so', 'https://www.google.com/s2/favicons?domain=granola.so&sz=128', 'PAID', 1, NULL, 'cat-14', NULL, NULL, 1777215011764, 1777215011764), ('t-96', 'otter', 'Otter', 'Otter.ai is a veteran of AI transcription, generating real-time transcripts, speaker-labelled notes, and auto-summaries for Zoom, Google Meet, and Teams. OtterPilot joins calls, captures action items, and syncs with Salesforce, HubSpot, Slack, and Notion. Its AI Chat answers questions across every past meeting. Used by VC firms for founder calls, partner meetings, and long-form interview diligence.', 'Transcription and meeting notes with real-time capture and AI chat over history', '["Transcribe and summarise founder pitches with speaker-labelled notes, timestamps, and action items","Query the meeting library for what a specific founder or expert said on a topic"]', '["Real-time transcripts with speaker-labelled notes and auto-summaries","OtterPilot joins calls and captures action items","AI Chat answers questions across the full meeting history"]', 'https://otter.ai', 'https://www.google.com/s2/favicons?domain=otter.ai&sz=128', 'FREEMIUM', 0, NULL, 'cat-14', NULL, NULL, 1777215011764, 1777215011764), ('t-97', 'aqua-voice', 'Aqua Voice', 'Aqua Voice is a desktop dictation tool for Mac and Windows built on its Avalon transcription model. It watches on-screen context to format output correctly, learns custom vocabulary for names and technical terms, and adapts tone between Slack, email, and docs across 49 languages. Used by VC investors to draft memo notes, Slack messages, and founder replies at speaking speed rather than typing.', 'Dictation app that turns speech into polished text across any Mac or Windows app', '["Dictate first-draft memo notes straight into Notion or Google Docs after a call","Fire off long Slack replies and founder emails without touching the keyboard"]', '["Avalon transcription model with on-screen context awareness","49 languages with tone matching across Slack, email, and docs"]', 'https://aquavoice.com', 'https://www.google.com/s2/favicons?domain=aquavoice.com&sz=128', 'PAID', 0, NULL, 'cat-15', NULL, NULL, 1777215011764, 1777215011764), ('t-98', 'superwhisper', 'Superwhisper', 'Superwhisper turns voice into polished text inside any app on macOS, Windows, or iOS. It runs offline, handles 100+ languages, and routes transcripts through GPT, Claude, or Llama for tone and format modes tuned to voice notes, Slack, or email. Push-to-talk and meeting recording round it out. Used by VC investors and founders who write faster by talking than typing.', 'Voice-to-text for Mac, Windows, iOS with offline mode and LLM post-processing', '["Dictate deal notes, founder emails, and Slack messages offline with custom vocabulary","Run voice transcripts through Claude or GPT for clean rewrites before sending"]', '["Offline mode across macOS, Windows, and iOS in 100+ languages","Routes transcripts through GPT, Claude, or Llama for tone modes"]', 'https://superwhisper.ai', 'https://www.google.com/s2/favicons?domain=superwhisper.ai&sz=128', 'PAID', 0, NULL, 'cat-15', NULL, NULL, 1777215011764, 1777215011764), ('t-99', 'willow-voice', 'Willow Voice', 'Willow Voice is a hotkey dictation app for Mac, Windows, and iPhone. Press the shortcut, talk, and it produces edited text with correct punctuation, names, and formatting across any app. AI mode turns short phrases into full messages, and style matching adapts tone per app. SOC 2 and HIPAA certified. Used by VC investors to draft emails, memos, and Slack messages by voice.', 'Hotkey dictation that cleans filler, matches your style, spells names right', '["Dictate structured follow-up emails to founders with names and terms spelled correctly","Draft first-pass memo sections by voice and edit the text rather than the transcript"]', '["AI mode turns short phrases into full messages with style matching","SOC 2 and HIPAA certified for sensitive workflows"]', 'https://willowvoice.com', 'https://www.google.com/s2/favicons?domain=willowvoice.com&sz=128', 'PAID', 0, NULL, 'cat-15', NULL, NULL, 1777215011764, 1777215011764), ('t-100', 'wispr-flow', 'Wispr Flow', 'Wispr Flow is the favourite voice-to-text agent for VC investors who write at speaking speed across Mac, Windows, iPhone, and Android. It transcribes speech, strips filler, and rewrites rambled thoughts into structured prose inside Gmail, Slack, Notion, VS Code, and 40+ other apps. Snippets turn repeated phrases — meeting links, scheduling info, firm disclaimers — into voice shortcuts. Style matches the tone of each app and Transform polishes voice into clean writing.', 'AI dictation that edits rambled speech into clean writing across any app', '["Voice memos — speak rambling thoughts and get publishable memo paragraphs written directly in Notion or Gmail","Snippets for repeats — trigger voice shortcuts for meeting links, scheduling info, addresses, and firm-template replies","Style and Transform — match the tone of each app and convert voice into clean, polished writing automatically"]', '["Voice-first input across Gmail, Slack, Notion, VS Code, and 40+ apps","Snippets for meeting links, scheduling info, and templates as voice shortcuts","Style matches each app''s tone, Transform polishes voice into clean writing"]', 'https://wisprflow.com', 'https://www.google.com/s2/favicons?domain=wisprflow.com&sz=128', 'PAID', 1, NULL, 'cat-15', NULL, NULL, 1777215011764, 1777215011764), ('t-102', 'coda', 'Coda', 'Coda is a workspace that combines docs, tables, and applications in one surface. Teams build hubs, trackers, and internal tools with formulas, buttons, and automations, while Coda AI writes content and automates columns at scale. 600+ integrations span Calendar, Slack, Figma, and Jira. Used by VC firms to build pipeline trackers, portfolio dashboards, and LP update drafts that would otherwise live across five tools.', 'Docs-meet-databases workspace with formulas, automations, and 600+ integrations', '["Build a dealflow tracker with owner views, stage automations, and synced Slack updates","Run portfolio KPI dashboards pulling data from Airtable, Notion, and Google Sheets"]', '["Docs, tables, and applications in one workspace surface","Coda AI writes content and automates columns at scale","600+ integrations spanning Calendar, Slack, Figma, and Jira"]', 'https://coda.io', 'https://www.google.com/s2/favicons?domain=coda.io&sz=128', 'FREEMIUM', 0, NULL, 'cat-16', NULL, NULL, 1777215011764, 1777215011764), ('t-103', 'google-sheets', 'Google Sheets', 'Google Sheets is the cloud spreadsheet inside Google Workspace. Multiple people edit at once with version history, granular sharing, and comments. Gemini writes formulas, builds tables, and analyses data on request, and smart chips pull in files, people, and dates from Drive. Used by VC firms for every model, cap-table snapshot, LP list, and portfolio tracker that demands more flex than a purpose-built CRM.', 'Collaborative cloud spreadsheet with real-time editing and Gemini AI assistance', '["Build fund models, pipeline trackers, and portfolio KPI sheets shared live with the team","Use Gemini to generate formulas and summarise data without writing spreadsheet syntax"]', '["Real-time collaborative editing with version history and comments","Gemini writes formulas, builds tables, and analyses data on request","Smart chips pulling files, people, and dates from Drive"]', 'https://google.com', 'https://www.google.com/s2/favicons?domain=google.com&sz=128', 'FREE', 1, NULL, 'cat-16', NULL, NULL, 1777215011764, 1777215011764), ('t-105', 'bolt', 'Bolt', 'Bolt.new turns a prompt or Figma import into a running web app. The agent writes the code, hooks up databases and authentication, and deploys to a custom domain with analytics in one flow. Design system templates from Shadcn, Chakra, Material UI, and others keep outputs presentable. Used by VC investors to spin up portfolio-facing microsites, landing pages, and internal tools without engineering time.', 'Prompt-to-app builder that ships hosted web apps with databases and auth', '["Prototype a thesis microsite or founder-facing landing page from a single prompt","Build lightweight internal tools for the fund without pulling in an engineer"]', '["Prompt or Figma import to a running web app","Hooks up databases, authentication, and analytics in one flow","Design system templates from Shadcn, Chakra, and Material UI"]', 'https://bolt.new', 'https://www.google.com/s2/favicons?domain=bolt.new&sz=128', 'FREEMIUM', 0, NULL, 'cat-17', NULL, NULL, 1777215011764, 1777215011764), ('t-106', 'emergent', 'Emergent', 'Emergent is a vibe-coding platform that turns natural language into production web and mobile apps, handling code, design, and deploy. Builders describe a product, and the agent ships it with LLM integrations, custom agents, and GitHub export on higher tiers. Used by VC investors to spin up internal tools, portfolio pages, and founder-facing prototypes without writing code or briefing engineers.', 'Natural-language builder for web and mobile apps with deployment and AI agents', '["Build an internal pipeline dashboard or portfolio portal from a plain-English spec","Ship a prototype of a thesis idea to share with founders before writing any code"]', '["Natural-language builder for production web and mobile apps","Custom agents and LLM integrations on higher tiers","GitHub export plus deploy in a single flow"]', 'https://emergent.sh', 'https://www.google.com/s2/favicons?domain=emergent.sh&sz=128', 'PAID', 0, NULL, 'cat-17', NULL, NULL, 1777215011764, 1777215011764), ('t-107', 'lovable', 'Lovable', 'Lovable builds web apps and sites from conversational prompts, screenshots, or reference docs. The AI generates a working prototype in real time, lets users iterate with follow-up instructions, and deploys in one click. It supports portfolios, SaaS products, and e-commerce. Used by VC investors and founders to test landing pages, internal tools, and MVPs without waiting on a development cycle.', 'AI app builder that turns a description or screenshot into a deployable web app', '["Prototype a founder idea or thesis microsite from a rough sketch in an afternoon","Build internal fund tools, portals, and dashboards without briefing an engineering team"]', '["Generates working web apps from prompts, screenshots, or reference docs","Real-time iteration with follow-up instructions","One-click deploy across portfolios, SaaS, and e-commerce templates"]', 'https://lovable.dev', 'https://www.google.com/s2/favicons?domain=lovable.dev&sz=128', 'FREEMIUM', 0, NULL, 'cat-17', NULL, NULL, 1777215011764, 1777215011764), ('t-108', 'replit', 'Replit', 'Replit is the production-grade browser IDE VC investors lean on for building real apps, not just prototypes — Agent 4 turns prompts into working full-stack code with hosting, authentication, databases, and monitoring all built in. 100+ integrations cover OpenAI, Stripe, and Google Workspace, and parallel agents handle multi-task work at once. Used by partners to ship internal tools, founder-facing prototypes, and even small revenue products without a local dev setup.', 'Browser IDE and AI agent that builds and hosts full-stack apps from a prompt', '["Internal tools — build pipeline trackers, founder directories, and dashboards from a prompt with hosting and auth handled","Founder prototypes — prototype thesis apps with working auth, database, and Stripe billing in one session","Production apps — ship small revenue products and portfolio tools that handle real users without a local dev setup"]', '["Agent 4 turns prompts into production-grade full-stack apps","Browser IDE with hosting, authentication, databases, and monitoring built in","100+ integrations and parallel agents for multi-task work"]', 'https://replit.com', 'https://www.google.com/s2/favicons?domain=replit.com&sz=128', 'FREEMIUM', 1, NULL, 'cat-17', NULL, NULL, 1777215011764, 1777215011764), ('t-110', 'arc-browser', 'Arc', 'A Chromium-based browser from The Browser Company that replaces the tab strip with a vertical sidebar, Spaces for separating work and personal contexts, and split view for side-by-side research. Profiles keep firm logins cleanly apart from personal browsing. Used by VC firms where associates live in the browser all day and want dealflow, diligence, and portfolio tabs organised by context rather than collapsed into one wall of favicons.', 'Opinionated browser built around Spaces, profiles, and focused work', '["Separate dealflow, portfolio, and personal browsing into distinct Spaces with their own tabs and logins","Split-view two data rooms or a deck and a CRM side by side during fast diligence reads"]', '["Spaces separate work and personal browsing contexts","Split view for side-by-side research across two pages"]', 'https://arc.net', 'https://www.google.com/s2/favicons?domain=arc.net&sz=128', 'FREE', 0, NULL, 'cat-18', NULL, NULL, 1777215011764, 1777215011764), ('t-111', 'atlas-browser', 'Atlas', 'OpenAI''s browser that ships ChatGPT as a sidebar on every page, with cursor chat to rewrite selected text, browser memories that carry context across sessions, and an agent mode that can navigate sites and fill forms on the user''s behalf. Chromium-based, macOS first. Early uptake among VC firms using it to ask questions of pitch decks, earnings pages, and founder sites without copy-pasting into a separate ChatGPT tab.', 'OpenAI''s Chromium browser with ChatGPT and an agent mode built in', '["Ask ChatGPT questions directly against an open pitch deck, founder site, or data room page","Run agent mode to pull structured data from portfolio dashboards or competitor pages into a memo"]', '["ChatGPT sidebar on every page with cursor chat for selected text","Agent mode navigates sites and fills forms autonomously"]', 'https://chatgpt.com', 'https://www.google.com/s2/favicons?domain=chatgpt.com&sz=128', 'FREE', 0, NULL, 'cat-18', NULL, NULL, 1777215011764, 1777215011764), ('t-112', 'brave', 'Brave', 'A Chromium-based browser that blocks third-party ads, trackers, and fingerprinting by default, loading pages noticeably faster than stock Chrome. Brave Search offers an independent index, Leo AI answers questions from inside the tab, and an optional VPN encrypts connections device-wide. Chosen by VC teams who want a clean second browser for competitor research, reading founder sites, and any session where they''d rather not ship behavioural data back to ad networks.', 'Privacy-first Chromium browser with ad blocking and Leo AI built in', '["Browse founder sites and competitor pages without cookies, trackers, or fingerprinting following you around","Run Leo AI queries against articles and decks while keeping prompts out of ad-network logs"]', '["Blocks third-party ads, trackers, and fingerprinting by default","Brave Search with an independent index and Leo AI assistant in-tab"]', 'https://brave.com', 'https://www.google.com/s2/favicons?domain=brave.com&sz=128', 'FREE', 0, NULL, 'cat-18', NULL, NULL, 1777215011764, 1777215011764), ('t-113', 'comet', 'Comet', 'Perplexity''s Chromium-based browser with the company''s assistant built into the address bar and sidebar. It answers questions with live citations, summarises open pages, and runs agentic tasks like drafting emails, filling forms, and pulling data across tabs. Went free in late 2025. Adopted by VC teams that already use Perplexity for research and want that same reasoning layer to stay with them across data rooms, LinkedIn profiles, and news tabs.', 'Perplexity''s AI browser with an agent that can research and act on pages', '["Summarise and compare open founder pages or data room documents without leaving the browser","Delegate repetitive research, form-filling, or contact-pulling tasks across multiple tabs to the built-in assistant agent"]', '["Perplexity assistant in the address bar and sidebar of every page","Agentic mode for drafting, form-filling, and cross-tab data pulls"]', 'https://perplexity.ai', 'https://www.google.com/s2/favicons?domain=perplexity.ai&sz=128', 'FREEMIUM', 0, NULL, 'cat-18', NULL, NULL, 1777215011764, 1777215011764), ('t-115', 'google-chrome', 'Google Chrome', 'The default browser for a large share of the working web, with profile sync, password manager, tab groups, and the Chrome Web Store ecosystem of extensions that almost every SaaS tool targets first. Gemini is integrated into the address bar for page-aware answers. Used by VC firms as the compatibility baseline where CRM extensions, LinkedIn scrapers, DocSend viewers, and deal-tracker plugins all just work without hunting for a Chromium equivalent.', 'The default browser for most of the web, now with Gemini built in', '["Run investor CRM, LinkedIn, and dealflow extensions against the broadest and most tested integration surface","Keep partner, associate, and personal profiles synced across laptop, phone, and backup machines"]', '["Gemini integrated into the address bar for page-aware answers","Chrome Web Store ecosystem of extensions almost every SaaS targets first"]', 'https://chrome.google.com', 'https://www.google.com/s2/favicons?domain=chrome.google.com&sz=128', 'FREE', 0, NULL, 'cat-18', NULL, NULL, 1777215011764, 1777215011764), ('t-65', 'carta', 'Carta', 'The incumbent platform for private-company equity, covering cap tables, 409A valuations, option grants, and secondary transactions, with a growing fund administration arm that handles capital calls, distributions, and LP reporting. Investors see portfolio ownership data flow straight from the companies they back. Used by VC firms both as the fund admin system of record and as the read-only view into cap tables at every Carta-hosted portfolio company they''ve invested in.', 'Cap table, 409A, and fund admin software for private markets', '["Run fund administration, capital calls, distributions, and LP statements from a single system of record","Track ownership, dilution, and option pool changes across every Carta-hosted portfolio company"]', '["Cap tables, 409A valuations, option grants, and secondary transactions","Fund admin handling capital calls, distributions, and LP statements"]', 'https://carta.com', 'https://www.google.com/s2/favicons?domain=carta.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-19', '["portfolio-management"]', NULL, 1777215011764, 1777215011764), ('t-117', 'bardeen', 'Bardeen', 'A workflow automation platform where AI agents run recurring GTM tasks: scraping LinkedIn and company sites, enriching contacts with validated emails and phones, qualifying leads against a described ICP, and pushing results into Sheets, Airtable, Notion, or a CRM. Templates cover most common flows. Used by VC platform and associate teams to pull structured data on founder universes, track competitor hiring, and keep dealflow trackers fed without manual copy-paste.', 'No-code AI agents that scrape, enrich, and route data between tools', '["Scrape LinkedIn searches or company lists and enrich each row with emails and firmographic fields","Auto-sync meeting notes, founder contacts, or competitor signals from sources into Airtable or Notion"]', '["No-code AI agents for scraping, enrichment, and routing","Pushes outputs into Sheets, Airtable, Notion, or any CRM"]', 'https://bardeen.ai', 'https://www.google.com/s2/favicons?domain=bardeen.ai&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, short_desc = excluded.short_desc, use_cases = excluded.use_cases, key_features = excluded.key_features, website_url = excluded.website_url, logo_url = excluded.logo_url, pricing_model = excluded.pricing_model, is_featured = excluded.is_featured, featured_order = excluded.featured_order, category_id = excluded.category_id, extra_category_slugs = excluded.extra_category_slugs, archived_at = excluded.archived_at, updated_at = excluded.updated_at;
INSERT INTO tools (id, slug, name, description, short_desc, use_cases, key_features, website_url, logo_url, pricing_model, is_featured, featured_order, category_id, extra_category_slugs, archived_at, created_at, updated_at) VALUES ('t-118', 'canva', 'Canva', 'The default design tool for teams without a designer, with templates for decks, social posts, one-pagers, event collateral, and print, plus AI generation for images, copy, and layouts. Brand kits lock fonts, colours, and logos across a team. Used by VC firms to produce LP update decks, portfolio announcement graphics, event flyers, and the steady drip of social content that marketing does not want to route through a freelance designer every time.', 'Drag-and-drop design platform for decks, social, and marketing assets', '["Build LP update decks, event flyers, and portfolio announcement graphics from on-brand templates","Let non-designers on the platform team ship social posts and one-pagers in minutes instead of days"]', '["Templates for decks, social, one-pagers, event collateral, and print","Brand kits lock fonts, colours, and logos across the team"]', 'https://canva.com', 'https://www.google.com/s2/favicons?domain=canva.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-119', 'chronicle-hq', 'Chronicle HQ', 'A presentation tool that turns notes, outlines, or existing docs into slides built from layouts designed by people who came from Apple, McKinsey, and BCG. Brand guidelines enforce fonts, colours, and visual rules across every deck, and exports go to PPT, PDF, or web. Used by VC firms that want external decks, LP updates, and market maps to land at a visual bar higher than Google Slides without routing every request through a design hire.', 'AI presentation builder with designer-grade layouts and brand guardrails', '["Turn a rough market map or thesis doc into an on-brand LP or external deck in one sitting","Enforce firm brand across partner, associate, and platform decks without manual template policing"]', '["Designer-grade layouts built by ex-Apple, McKinsey, and BCG designers","Brand guidelines enforce fonts, colours, and rules across every deck","Exports to PowerPoint, PDF, or web from the same source"]', 'https://chroniclehq.com', 'https://www.google.com/s2/favicons?domain=chroniclehq.com&sz=128', 'PAID', 1, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-120', 'circle', 'Circle', 'A community platform that bundles discussion spaces, live events, courses, paid memberships, branded iOS and Android apps, email broadcasts, and AI agents trained on community content. Creators and operators run the whole member experience from one place instead of stitching Slack, Teachable, and Stripe together. Used by VC firms to host founder communities, LP knowledge hubs, and platform programmes where threaded discussion and gated content matter more than real-time chat.', 'Branded community platform with spaces, courses, events, and payments', '["Host a founder or operator community with spaces, events, and gated content behind a firm-branded app","Run a paid LP or limited-partner programme with memberships, courses, and private discussion rooms"]', '["Discussion spaces, live events, and courses in one platform","Paid memberships and AI agents trained on community content"]', 'https://circle.so', 'https://www.google.com/s2/favicons?domain=circle.so&sz=128', 'PAID', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-122', 'docsend', 'DocSend', 'A document sharing service that replaces PDF attachments with trackable links, surfacing who opened a deck, which pages they lingered on, how long they spent, and whether they forwarded it. Access can be gated by email, expiration, or NDA. Used on both sides of the VC table: founders track which investors actually read the deck, and investors route sensitive memos, data rooms, and LP materials through DocSend to see exactly how they were consumed.', 'Secure document sharing with page-by-page analytics for decks and memos', '["Send pitch decks or LP memos as tracked links and see page-level engagement per recipient","Gate data rooms with email verification, NDAs, and expiry instead of shipping raw PDFs"]', '["Trackable links replace PDF attachments with page-by-page analytics","Access gated by email verification, expiration, or NDA"]', 'https://docsend.com', 'https://www.google.com/s2/favicons?domain=docsend.com&sz=128', 'PAID', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-123', 'exa', 'Exa', 'A web search API designed for LLMs rather than humans, with specialised indexes for people, companies, code docs, financial data, and news, plus structured output schemas and highlight extraction that cuts token costs. Sub-180ms latency, SOC 2 Type II, zero data retention. Used by VC teams and the tools they build on top to power founder discovery, competitor mapping, and diligence agents that need clean, citation-backed retrieval instead of scraped Google results.', 'Neural search API built for AI agents and structured research workflows', '["Power internal founder-discovery or competitor-mapping agents with structured, citation-backed search over news and company pages","Enrich dealflow records by extracting named entities and highlights from company and news pages"]', '["Neural search API tuned for AI agents, not humans","Sub-180ms latency, structured outputs, SOC 2 Type II, zero retention"]', 'https://exa.ai', 'https://www.google.com/s2/favicons?domain=exa.ai&sz=128', 'PAID', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-124', 'gamma', 'Gamma', 'An AI tool that turns a prompt, outline, or pasted doc into a polished deck, written document, or one-page website in a responsive card format that adapts to any screen. Built-in templates, charts, and image generation cover most business content needs. Used by VC firms to rough out thesis decks, LP updates, market maps, and event microsites in the time it used to take to open a PowerPoint template and align the first text box.', 'AI generator for decks, documents, and webpages from a single prompt', '["Draft thesis decks, market maps, or LP updates from a prompt or existing memo in minutes","Spin up a lightweight event page or portfolio microsite without a designer or web build"]', '["Prompt or doc to a polished deck, document, or webpage","Responsive card format that adapts to any screen"]', 'https://gamma.app', 'https://www.google.com/s2/favicons?domain=gamma.app&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-125', 'getro', 'Getro', 'Getro powers branded job boards and talent networks for investor communities, aggregating open roles across portfolio companies and matching candidates to founders who are hiring. The platform tracks intros, applicants, and successful hires with reporting on network ROI. Used by VC firms to run a portfolio jobs hub, surface warm candidate intros, and prove the value of platform work to LPs and founders.', 'Branded job boards and talent networks built for VC platform teams', '["Run a branded jobs board that aggregates every open role across the portfolio automatically","Make warm candidate introductions at scale and track which hires actually close"]', '["Branded job boards aggregating roles across the portfolio","AI-matched warm introductions for hiring, sales, and BD","Outcome tracking on intros, hires, and pipeline ROI"]', 'https://getro.com', 'https://www.google.com/s2/favicons?domain=getro.com&sz=128', 'PAID', 1, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-126', 'gumloop', 'Gumloop', 'Gumloop is a visual canvas for building AI agents that connect LLMs to tools like Slack, HubSpot, Salesforce, and internal databases. Teams drag nodes to define multi-step workflows, schedule recurring runs, and trigger agents from chat. Multi-model support keeps the firm off a single vendor. Used by VC firms to automate deck summarisation, inbound deal triage, and portfolio data pulls without writing code.', 'No-code AI automation platform for building and running agent workflows', '["Automate inbound deal triage by scoring decks and routing them to the right partner","Build a recurring agent that monitors portfolio company news and flags material signals"]', '["Visual canvas for building multi-step AI agents","Multi-model support keeps the firm off a single vendor"]', 'https://gumloop.com', 'https://www.google.com/s2/favicons?domain=gumloop.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-127', 'icypeas', 'Icypeas', 'Icypeas finds work email addresses from a name and company, verifies deliverability including catch-all domains, and runs reverse lookups that map an email to a LinkedIn profile. The database refreshes monthly against one billion records and the API plugs into outreach tools. Used by VC firms to enrich founder lists, find warm contacts inside a target company, and keep CRM records clean before a campaign.', 'Email finder and verifier that turns names or domains into verified contacts', '["Enrich a sourcing list with verified founder emails before a cold outbound campaign","Reverse-lookup an unknown email from inbound traffic to identify the sender and company"]', '["Email finder turning name and company into verified contact","Reverse lookup mapping any email to a LinkedIn profile"]', 'https://icypeas.com', 'https://www.google.com/s2/favicons?domain=icypeas.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-128', 'luma', 'Luma', 'Luma turns an event into a single shareable page: guests RSVP, get email and SMS reminders, and check in on arrival. Hosts manage the guest list, sell tickets, and message attendees from one dashboard. Around two million people sign up through Luma every month. Widely used by VC firms to run founder dinners, demo days, LP mixers, and office hours without stitching together Mailchimp, Eventbrite, and a spreadsheet.', 'Event pages with invites, RSVPs, ticketing, and check-in in one link', '["Host a founder dinner with invites, RSVPs, waitlist, and check-in from one event page","Run a demo day or LP mixer with ticketing, reminders, and a shared attendee directory"]', '["Single-link event page with RSVPs, waitlist, and check-in","Email and SMS reminders to guests automatically"]', 'https://lu.ma', 'https://www.google.com/s2/favicons?domain=lu.ma&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-129', 'mailchimp', 'Mailchimp', 'Mailchimp is an email and SMS marketing platform with a drag-and-drop designer, audience segmentation, automation flows, and analytics that tie campaigns back to revenue. Integrations cover Shopify, Stripe, and a long tail of CRMs. Owned by Intuit and used by millions of small and mid-market teams. Used by VC firms to send LP letters, founder newsletters, and portfolio update digests with tracking on who actually opened the email.', 'Email and SMS marketing platform with automation and audience segmentation', '["Send quarterly LP letters and portfolio updates with open, click, and engagement tracking","Run a founder newsletter that segments recipients by sector, stage, or relationship warmth"]', '["Drag-and-drop email designer with audience segmentation","Integrations with Shopify, Stripe, and a long tail of CRMs"]', 'https://mailchimp.com', 'https://www.google.com/s2/favicons?domain=mailchimp.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-130', 'medium', 'Medium', 'Medium is a publishing platform where writers post essays and longer pieces into a shared discovery feed rather than a private blog. Topic-based publications, recommendations, and a paid membership give stories reach without the owner running SEO or a newsletter list. The editor handles formatting and images cleanly. Used by VC firms and partners to publish thesis pieces, market maps, and portfolio announcements that surface to a wider founder and operator audience.', 'Publishing platform for long-form essays with built-in reader distribution', '["Publish a sector thesis or market map that reaches founders through Medium''s discovery feed","Run a firm publication where every partner posts memos, playbooks, and portfolio stories"]', '["Shared discovery feed surfaces stories beyond a private blog","Paid membership tier and clean editor for long-form posts"]', 'https://medium.com', 'https://www.google.com/s2/favicons?domain=medium.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-131', 'raycast', 'Raycast', 'Raycast is a keyboard launcher that replaces Spotlight with AI, snippets, window management, and a library of over a thousand extensions covering Slack, Notion, Linear, GitHub, and most SaaS tools. Quick AI answers sit behind a hotkey, so drafting and lookup happen without switching apps. Used by VC firms for fast CRM search, quick AI drafts during a call, and snippets that paste the firm''s template replies into email.', 'Keyboard-first Mac launcher with AI, snippets, and a deep extension library', '["Search Affinity, Notion, and Slack from a single hotkey without opening each app","Fire a Quick AI prompt mid-meeting to draft a memo section or summarise a decision"]', '["1,000+ extensions covering Slack, Notion, Linear, GitHub, and most SaaS","Quick AI hotkey for drafting and lookup without app switching"]', 'https://raycast.com', 'https://www.google.com/s2/favicons?domain=raycast.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-132', 'substack', 'Substack', 'Substack is a publishing platform that combines email newsletters, podcasts, and a native app feed with paid subscriptions and reader discussions. Writers keep the subscriber list, Substack handles payments, hosting, and recommendations that grow the list from other newsletters. Widely used by VC investors to run a thesis newsletter, build reputation with founders, and sometimes monetise a paid tier that funds the research behind it.', 'Newsletter platform with paid subscriptions, podcasts, and reader discussion', '["Run a public thesis newsletter that compounds inbound dealflow from founders who subscribe","Publish interviews and market notes to a paid tier that funds the research underneath"]', '["Email newsletters, podcasts, and a native app feed in one platform","Paid subscriptions with payments, hosting, and reader discussion"]', 'https://substack.com', 'https://www.google.com/s2/favicons?domain=substack.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-133', 'tally', 'Tally', 'Tally is a form builder where you type fields into a document rather than dragging them onto a canvas, and every core feature including unlimited forms and submissions is free. Conditional logic, calculations, file uploads, e-signatures, and Stripe payments are built in, with integrations for Notion, Google Sheets, Airtable, and Slack. Used by VC firms for inbound deal intake forms, founder feedback surveys, and event RSVPs that pipe into the dealflow database.', 'Free form builder with conditional logic, payments, and Notion-style editing', '["Collect inbound decks through a branded intake form that writes directly into Notion or Airtable","Run a quick portfolio founder survey with conditional questions and responses routed to Slack"]', '["Doc-style form builder with unlimited forms and submissions on the free tier","Conditional logic, calculations, file uploads, and e-signatures","Stripe payments and integrations with Notion, Sheets, Airtable, Slack"]', 'https://tally.so', 'https://www.google.com/s2/favicons?domain=tally.so&sz=128', 'FREEMIUM', 1, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-135', 'typeform', 'Typeform', 'Typeform builds forms that ask one question at a time with a conversational feel, driving higher completion rates than traditional grid surveys. AI helps generate the form from a prompt, and integrations cover Slack, HubSpot, Mailchimp, and hundreds more. Interactive video and logic jumps let responses branch in real time. Used by VC firms for founder intake, LP surveys, and event feedback where completion quality matters more than raw field count.', 'Conversational forms with AI-assisted building and interactive design', '["Build a branded founder intake form that feels like a conversation rather than a grid","Run an LP survey with logic jumps that route questions based on fund size and geography"]', '["Conversational forms one question at a time for higher completion","Logic jumps and interactive video plus 100+ integrations"]', 'https://typeform.com', 'https://www.google.com/s2/favicons?domain=typeform.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-136', 'webflow', 'Webflow', 'Webflow is a visual development platform for production websites, combining a designer that outputs clean HTML and CSS, a CMS for dynamic content, managed hosting with a global CDN, and AI tools for SEO and personalisation. Teams ship without a frontend engineer while keeping pixel control. Used by VC firms to run the public fund site, portfolio company pages, and thesis microsites without waiting for an agency each time copy changes.', 'Visual website builder with CMS, hosting, and AI optimisation built in', '["Ship and maintain the fund website and portfolio page without a developer in the loop","Spin up a thesis microsite or event landing page with a CMS the whole team can edit"]', '["Visual designer outputting clean HTML and CSS","CMS for dynamic content with managed hosting on a global CDN"]', 'https://webflow.com', 'https://www.google.com/s2/favicons?domain=webflow.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-137', 'wizikey', 'Wizikey', 'Wizikey is a media monitoring platform that tracks brand, competitor, and industry mentions across online, print, broadcast, and social in one dashboard, with sentiment analysis, real-time alerts, and coverage benchmarking. AI assists storytelling and reporting for PR teams. Used by VC firms and their portfolio comms teams to watch founder and portfolio coverage, benchmark share of voice against rivals, and catch negative press before it reaches the partner meeting.', 'AI media monitoring across online, print, broadcast, and social channels', '["Monitor press coverage across the portfolio and alert the team on negative sentiment spikes","Benchmark a portfolio company''s share of voice against named competitors each quarter"]', '["AI media monitoring across online, print, broadcast, and social","Real-time alerts and sentiment analysis on coverage"]', 'https://wizikey.com', 'https://www.google.com/s2/favicons?domain=wizikey.com&sz=128', 'PAID', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764), ('t-138', 'zoom', 'Zoom', 'Zoom is the default video meeting tool for most firms, now a wider workplace platform with chat, phone, webinars, docs, and AI Companion that summarises meetings and drafts follow-ups. Recordings, transcripts, and whiteboards persist after the call. Used by VC firms for founder pitches, partner meetings, and LP calls, with AI-generated notes feeding back into the CRM so every conversation leaves a durable, searchable record.', 'Video meetings, webinars, and AI note-taking on a unified comms platform', '["Run founder pitches and partner meetings with AI summaries auto-filed to the CRM","Host an LP update webinar with registration, recording, and a searchable transcript afterwards"]', '["Video meetings, webinars, and team chat in one platform","AI Companion summarises meetings and drafts follow-ups","Recordings, transcripts, and whiteboards persist after the call"]', 'https://zoom.us', 'https://www.google.com/s2/favicons?domain=zoom.us&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777215011764, 1777215011764) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, short_desc = excluded.short_desc, use_cases = excluded.use_cases, key_features = excluded.key_features, website_url = excluded.website_url, logo_url = excluded.logo_url, pricing_model = excluded.pricing_model, is_featured = excluded.is_featured, featured_order = excluded.featured_order, category_id = excluded.category_id, extra_category_slugs = excluded.extra_category_slugs, archived_at = excluded.archived_at, updated_at = excluded.updated_at;

